/// Build a [security.txt](https://datatracker.ietf.org/doc/html/rfc9116) body
/// from environment configuration. Operators set:
///
/// - `EMEM_TLS_CONTACT` — `mailto:` or `https:` URI for security reports.
/// - `EMEM_PUBLIC_URL` — origin for the `Canonical:` field (e.g.
///   `https://emem.dev`); falls back to the first domain in
///   `EMEM_TLS_DOMAINS`. If neither is set, `Canonical:` is omitted.
/// - `EMEM_SECURITY_POLICY_URL` — optional URL for `Policy:`.
///
/// `Expires:` is computed at render time as now + 365d (RFC 9116 recommends
/// ≤1 year), so a long-running responder never serves a stale expiry.
fn build_security_txt() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let mut out = String::new();
    if let Ok(contact) = std::env::var("EMEM_TLS_CONTACT") {
        let c = contact.trim();
        if !c.is_empty() {
            out.push_str("Contact: ");
            out.push_str(c);
            out.push('\n');
        }
    }
    if let Some(origin) = public_origin() {
        out.push_str("Canonical: ");
        out.push_str(&origin);
        out.push_str("/.well-known/security.txt\n");
    }
    let secs = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0)
        + 365 * 24 * 60 * 60;
    out.push_str(&format!("Expires: {}\n", iso8601_utc(secs)));
    out.push_str("Preferred-Languages: en\n");
    if let Ok(policy) = std::env::var("EMEM_SECURITY_POLICY_URL") {
        let p = policy.trim();
        if !p.is_empty() {
            out.push_str("Policy: ");
            out.push_str(p);
            out.push('\n');
        }
    }
    out
}

/// Returns the configured public origin (no trailing slash), or `None` if
/// neither `EMEM_PUBLIC_URL` nor `EMEM_TLS_DOMAINS` is set.
fn public_origin() -> Option<String> {
    if let Ok(u) = std::env::var("EMEM_PUBLIC_URL") {
        let u = u.trim().trim_end_matches('/');
        if !u.is_empty() {
            return Some(u.to_string());
        }
    }
    if let Ok(domains) = std::env::var("EMEM_TLS_DOMAINS") {
        let first = domains.split(',').next().unwrap_or("").trim();
        if !first.is_empty() {
            return Some(format!("https://{first}"));
        }
    }
    None
}

/// Render `secs` (Unix epoch seconds) as RFC 3339 / ISO 8601 UTC.
fn iso8601_utc(secs: u64) -> String {
    // Days since epoch + civil-from-days (Howard Hinnant) — avoids pulling chrono
    // for one timestamp formatter.
    let days = (secs / 86_400) as i64;
    let sod = (secs % 86_400) as u32;
    let (y, m, d) = civil_from_days(days);
    let hh = sod / 3600;
    let mm = (sod / 60) % 60;
    let ss = sod % 60;
    format!("{y:04}-{m:02}-{d:02}T{hh:02}:{mm:02}:{ss:02}Z")
}

/// Convert civil (Y, M, D) → days since 1970-01-01 (the inverse of
/// `civil_from_days`). Same Hinnant reference; works for any year in the
/// proleptic Gregorian calendar without pulling chrono.
fn days_from_civil(y: i32, m: u32, d: u32) -> i64 {
    let y = if m <= 2 { y - 1 } else { y } as i64;
    let m = m as i64;
    let d = d as i64;
    let era = if y >= 0 { y } else { y - 399 } / 400;
    let yoe = y - era * 400;
    let mp = if m > 2 { m - 3 } else { m + 9 };
    let doy = (153 * mp + 2) / 5 + d - 1;
    let doe = yoe * 365 + yoe / 4 - yoe / 100 + doy;
    era * 146_097 + doe - 719_468
}

/// Unix epoch seconds for `YYYY-01-01T00:00:00Z`. Used as the canonical
/// per-year anchor for annual-snapshot bands like Tessera.
fn jan1_unix(year: i32) -> i64 {
    days_from_civil(year, 1, 1) * 86_400
}

/// Convert days since 1970-01-01 to civil (Y, M, D). Algorithm by Howard
/// Hinnant — overflow-safe for any plausible epoch second.
fn civil_from_days(z: i64) -> (i32, u32, u32) {
    let z = z + 719_468;
    let era = if z >= 0 { z } else { z - 146_096 } / 146_097;
    let doe = (z - era * 146_097) as u64;
    let yoe = (doe - doe / 1_460 + doe / 36_524 - doe / 146_096) / 365;
    let y = yoe as i64 + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
    let mp = (5 * doy + 2) / 153;
    let d = (doy - (153 * mp + 2) / 5 + 1) as u32;
    let m = if mp < 10 { mp + 3 } else { mp - 9 } as u32;
    let y = if m <= 2 { y + 1 } else { y };
    (y as i32, m, d)
}
async fn ai_plugin() -> Response {
    text_response("application/json; charset=utf-8", AI_PLUGIN_JSON)
}
async fn agent_manifest() -> Response {
    text_response("application/json; charset=utf-8", AGENT_JSON)
}

/// `GET /.well-known/agent-card.json` — A2A (Agent2Agent) protocol agent
/// card. Microsoft Agent Framework, Google Gemini CLI, and the broader A2A
/// steering committee (AWS / Cisco / IBM / Salesforce / SAP / ServiceNow)
/// all auto-discover agents at this path. The schema mirrors A2A v0.2:
/// name, description, url, capabilities, skills, securitySchemes,
/// provider. We declare emem as a free, no-auth read-only agent and list
/// every primitive as a skill (deduplicated from `emem_mcp::TOOLS`).
async fn well_known_agent_card(State(s): State<AppState>) -> Json<JsonValue> {
    let origin = public_origin().unwrap_or_else(|| "https://emem.dev".into());
    // Skill tags must be a deduplicated set of editorial labels — earlier
    // version emitted `[t.category, read|write]` which produced
    // `["read","read"]` for every Read primitive (16 of 30 skills). A2A
    // importers (Vertex Agent Builder, Microsoft Copilot Studio) flatten
    // tags into a chip row, so duplicates surface as visible UI noise.
    // We now emit category + level only (level is L0/L1, distinct).
    let skills: Vec<JsonValue> = emem_mcp::TOOLS
        .iter()
        .map(|t| {
            let cat = match t.category {
                emem_mcp::ToolCategory::Read => "read",
                emem_mcp::ToolCategory::Write => "write",
                emem_mcp::ToolCategory::Verify => "verify",
                emem_mcp::ToolCategory::Introspect => "introspect",
                emem_mcp::ToolCategory::Plan => "plan",
            };
            json!({
                "id":          t.name,
                "name":        t.title,
                "description": t.description,
                "tags":        [cat, t.level],
                "examples":    [t.when_to_use],
            })
        })
        .collect();
    Json(json!({
        // A2A protocol envelope (https://a2a-protocol.org/latest/topics/agent-discovery/)
        "protocolVersion":    "0.2",
        "name":               "emem",
        "description":        "Agent-native, content-addressed, ed25519-signed Earth memory protocol. Recall any place on Earth (cell × band × tslot) and get back a signed receipt with a content address you can cite.",
        "url":                format!("{origin}/mcp"),
        "preferredTransport": "HTTP+JSON",
        "version":            env!("CARGO_PKG_VERSION"),
        "documentationUrl":   "https://emem.dev/agents.md",
        "iconUrl":            format!("{origin}/favicon.svg"),
        "capabilities": {
            "streaming":            false,
            "pushNotifications":    false,
            "stateTransitionHistory": true,
        },
        "defaultInputModes":  ["text/plain", "application/json"],
        "defaultOutputModes": ["application/json"],
        "skills": skills,
        "securitySchemes": {
            "none": { "type": "noAuth" }
        },
        "security": [{ "none": [] }],
        "provider": {
            "organization": "Vortx AI Private Limited",
            "url":          "https://vortx.ai",
            "contact":      "avijeet@vortx.ai",
            "country":      "India",
            "privacy_policy_url":   format!("{origin}/privacy"),
            "terms_of_service_url": format!("{origin}/terms"),
            "support_url":          format!("{origin}/support"),
            "data_protection": {
                "regimes":  ["GDPR", "UK-GDPR", "DPDP-2023", "CCPA-CPRA"],
                "contact":  "avijeet@vortx.ai",
                "no_pii_in_canonical_channel": true,
                "ip_handling": "blake3-truncated-8B (one-way hash of client IP)",
                "log_retention_days": 30,
                "log_retention_enforced_by": "systemd-journald MaxRetentionSec=30day",
                "sells_personal_data": false,
                "shares_for_advertising": false,
                "third_party_analytics": match ga_measurement_id() {
                    Some(id) => json!([{
                        "vendor":           "Google Analytics 4",
                        "measurement_id":   id,
                        "ga_post_consent_cookies": [
                            "_ga (2yr)",
                            format!("_ga_{} (2yr)", id.trim_start_matches("G-")),
                        ],
                        "scope":            "HTML landing page only (/), not /v1/*, /mcp, /openapi.json, /agents.md, /llms.txt, or .well-known/*",
                        "configured_via":   "env var EMEM_GA_MEASUREMENT_ID; repo holds a placeholder so forks do not inherit",
                        "consent_mode":     "v2",
                        "consent_default":  "denied for ad_storage, ad_user_data, ad_personalization, analytics_storage, functionality_storage, personalization_storage; granted for security_storage",
                        "consent_banner": {
                            "rendered_for":          "human visitors with a JS-capable browser",
                            "rendered_for_ai_agents": false,
                            "buttons":               ["Accept", "Reject"],
                            "buttons_equal_prominence": true,
                            "esc_key_action":        "Reject",
                            "is_cookie_wall":        false,
                            "decision_storage":      "first-party cookie emem_consent (Path=/, Max-Age=180d, SameSite=Lax, Secure)",
                            "decision_storage_rationale": "switched from localStorage in 2026-05; EU-strict browser configs (Firefox Strict, Brave Shields, 'delete site data on close') were clearing localStorage between sessions and causing the banner to re-prompt on every refresh. First-party cookies survive those configs.",
                            "revocation":            "footer 'Manage cookies' link deletes the cookie and reopens the banner",
                        },
                        "cookies_pre_consent":  [],
                        "cookies_post_decision": ["emem_consent (180d, necessary, ePrivacy Art. 5(3) exempt)"],
                        "cookies_post_accept":   ["emem_consent (180d, necessary)", "_ga (2yr)", "_ga_<container> (2yr)"],
                        "pii_transmitted_pre_consent": false,
                        "ip_transmitted_pre_consent":  false,
                        "transport":        "navigator.sendBeacon (non-blocking)",
                        "transfer_basis":   "Google TADPF self-certification + SCCs",
                        "opt_out":          "https://tools.google.com/dlpage/gaoptout",
                        "lawful_basis_pre_consent":  "GDPR Art. 6 not engaged (no personal data processed)",
                        "lawful_basis_post_consent": "GDPR Art. 6(1)(a) consent",
                    }]),
                    None => json!([]),
                },
            },
        },
        // A2A v0.3 constrains `transport` to JSONRPC|HTTP|SSE|HTTP+JSON|GRPC.
        // Earlier custom values ("openapi-3.1", "mcp-streamable-http", …)
        // were silently dropped by Vertex / Copilot Studio importers — they
        // saw zero alternate interfaces. We now use spec-valid transports
        // and keep the surface kind in `protocol` (extension field).
        "additionalInterfaces": [
            { "url": format!("{origin}/openapi.json"),          "transport": "HTTP+JSON", "protocol": "openapi-3.1" },
            { "url": format!("{origin}/.well-known/emem.json"), "transport": "HTTP+JSON", "protocol": "well-known-json" },
            { "url": format!("{origin}/v1/agent_card"),         "transport": "HTTP+JSON", "protocol": "agent-card-v1" },
            { "url": format!("{origin}/mcp"),                   "transport": "JSONRPC",   "protocol": "mcp-streamable-http" },
        ],
        "responder": {
            "pubkey_b32":    data_encoding::BASE32_NOPAD.encode(&s.identity.pubkey.0).to_lowercase(),
            "signature_alg": "ed25519",
            "hash_alg":      "blake3",
        },
    }))
}

/// `GET /.well-known/mcp.json` — direct MCP server discovery descriptor.
/// Newer MCP clients (Cursor 0.30+, VS Code Copilot Chat MCP, Claude
/// Desktop ≥ 0.10, Continue, Cline, Open WebUI) probe this path before
/// asking the user to paste a config blob, so a present + correct
/// document means the user can install with one URL instead of seven
/// JSON fields. Schema mirrors the mcpServers entry shape used by every
/// major client so the same doc works everywhere.
async fn well_known_mcp(State(s): State<AppState>) -> Json<JsonValue> {
    let origin = public_origin().unwrap_or_else(|| "https://emem.dev".into());
    let pubkey_b32 = data_encoding::BASE32_NOPAD
        .encode(&s.identity.pubkey.0)
        .to_lowercase();
    let tools: Vec<&str> = emem_mcp::TOOLS.iter().map(|t| t.name).collect();
    Json(json!({
        "$schema":     "https://modelcontextprotocol.io/schemas/draft/well-known-mcp.json",
        "name":        "emem",
        "version":     env!("CARGO_PKG_VERSION"),
        "description": "Cite-able, content-addressed, signed Earth memory protocol. cell × band × tslot. Every read returns an ed25519 receipt. No API keys for L0/L1.",
        "homepage":    "https://emem.dev",
        "documentation": format!("{origin}/agents.md"),
        "icon":        format!("{origin}/favicon.svg"),
        "license":     "Apache-2.0",
        "operator": {
            "name":    "Vortx AI Private Limited",
            "country": "India",
            "contact": "avijeet@vortx.ai",
            "url":     "https://vortx.ai",
        },
        // Universal mcpServers shape — the same blob a user would paste
        // into Claude Desktop / Cursor / Cline / Gemini CLI / Continue
        // / Open WebUI. Clients that auto-install pull this directly.
        "mcpServers": {
            "emem": {
                "url":         format!("{origin}/mcp"),
                "transport":   "streamable-http",
                "description": "Earth memory protocol — recall, compare, find_similar, diff, trajectory, verify over signed receipts.",
            }
        },
        // Capability surface so the client can decide whether to install
        // without round-tripping initialize.
        "capabilities": {
            "tools":     { "count": tools.len(), "listChanged": false },
            "resources": { "listChanged": false, "subscribe": false },
            "prompts":   { "listChanged": false },
            "auth":      { "type": "none", "required": false },
            "transport": ["streamable-http", "http+json"],
            "protocol_versions": ["2024-11-05", "2025-03-26", "2025-06-18"],
        },
        "tools": tools,
        "discovery": {
            "openapi":              format!("{origin}/openapi.json"),
            "agent_card":           format!("{origin}/v1/agent_card"),
            "agent_card_a2a":       format!("{origin}/.well-known/agent-card.json"),
            "well_known_emem":      format!("{origin}/.well-known/emem.json"),
            "oauth_protected_resource": format!("{origin}/.well-known/oauth-protected-resource"),
            "llms_txt":             format!("{origin}/llms.txt"),
            "llms_full_txt":        format!("{origin}/llms-full.txt"),
        },
        "responder": {
            "pubkey_b32":    pubkey_b32,
            "signature_alg": "ed25519",
            "hash_alg":      "blake3",
        },
    }))
}

/// `GET /.well-known/oauth-protected-resource` — RFC 9728 protected
/// resource metadata. The hosted instance is *no-auth* read-only, but
/// Anthropic's MCP broker (and others) probe this path before falling
/// through to anonymous. Publishing an explicit "no-auth" doc avoids a
/// silent 404 → conservative-default → host-allowlist failure mode.
async fn well_known_oauth_protected_resource() -> Json<JsonValue> {
    let origin = public_origin().unwrap_or_else(|| "https://emem.dev".into());
    Json(json!({
        // RFC 9728 OAuth 2.0 Protected Resource Metadata
        "resource":                       format!("{origin}/mcp"),
        "authorization_servers":          [],
        "bearer_methods_supported":       [],
        "resource_documentation":         format!("{origin}/agents.md"),
        "scopes_supported":               [],
        "resource_signing_alg_values_supported": ["EdDSA"],
        // Non-standard but read by some MCP brokers — declare auth=none
        // explicitly so a directory reviewer / client-side broker doesn't
        // assume DCR is required.
        "auth":                           "none",
        "auth_required":                  false,
        "notes":                          "L0 / L1 reads are anonymous. L2 writes (attest, challenge) require an ed25519 attester key submitted via /v1/attest_cbor; no OAuth is involved in any flow.",
    }))
}

