async fn functions() -> Json<JsonValue> {
    Json(serde_json::to_value(&*emem_core::functions::DEFAULT).unwrap_or(json!({})))
}

async fn sources() -> Json<JsonValue> {
    Json(serde_json::to_value(&*emem_core::sources::DEFAULT).unwrap_or(json!({})))
}

/// `GET /v1/algorithms` — content-addressed algorithm registry.
///
/// Composition recipes that fuse already-attested band facts (and
/// embeddings) into derived scores, classifications, and similarity
/// metrics. Distinct from `/v1/functions` (which derives a single band
/// value from raw upstream sources) and from `/v1/bands` (the data slot
/// itself). Receipts that quote a derived score should cite
/// `algorithm_cid` alongside the input `fact_cids` so a downstream
/// verifier can replay the same composition.
///
/// Three kinds: `solo` (one band → derived), `combined` (multi-band
/// composite), `embedding` (operations on the geotessera vector).
/// Process-wide cached algorithms_cid — the registry is content-addressed
/// and immutable for the life of the process, so we hash it once and
/// reuse the string everywhere it's surfaced (/health, /v1/manifests,
/// /v1/discover, /v1/agent_card, /v1/algorithms, /v1/intent, /.well-known).
static ALGORITHMS_CID: LazyLock<Option<String>> =
    LazyLock::new(|| emem_core::manifest::manifest_cid(&*emem_core::algorithms::DEFAULT).ok());

/// Process-wide cached topics_cid — the topic registry (`topics-v0.json`)
/// is content-addressed and immutable for the life of the process. The
/// CID is surfaced on `/v1/manifests` so an agent can pin which routing
/// taxonomy was active when its receipt was issued, and dual-write a
/// new taxonomy without breaking older receipts.
static TOPICS_CID: LazyLock<Option<String>> =
    LazyLock::new(|| emem_core::manifest::manifest_cid(&*emem_core::topics::DEFAULT).ok());

/// Pagination + projection options for `/v1/algorithms` and
/// `/v1/materializers`. Both endpoints used to return the entire registry
/// in a single response (190 KB and 62 KB respectively at 0.0.4) which
/// blew through MCP's 25 KB cap and silently truncated against agent
/// context windows. The handlers now accept `?page=N&page_size=K` (clamped
/// to 1..=100) and an optional `?summary=true` projection that drops the
/// long `formula` body and `temporal_recipe` so an agent can browse the
/// catalog cheaply, then GET `/v1/algorithms/<key>` for one entry's full
/// detail.
///
/// The default behaviour with NO query params still returns page 1 — never
/// the full set — so MCP responses stay bounded by default and agents
/// learn to iterate. The response body always carries `pagination.total`
/// and `pagination.has_next` so the slicing is honest.
#[derive(serde::Deserialize, Default, Debug, Clone)]
struct PageQuery {
    /// 1-indexed page number. Defaults to `1` when absent.
    #[serde(default)]
    page: Option<usize>,
    /// Items per page. Defaults to `20`, clamped to `1..=100`.
    #[serde(default)]
    page_size: Option<usize>,
    /// When `true`, drop the long `formula` / `notes` body and
    /// `temporal_recipe` so each entry stays compact.
    #[serde(default)]
    summary: Option<bool>,
}

/// Default page size when the caller omits `?page_size=`. Held in one
/// place so the test that pins the clamp also pins the default.
const PAGINATION_DEFAULT_PAGE_SIZE: usize = 20;
/// Hard cap on `page_size` — anything above this is silently clamped so
/// a runaway client can't ask for the full registry in one shot.
const PAGINATION_MAX_PAGE_SIZE: usize = 100;

/// Resolve `(page, page_size)` from a `PageQuery`, applying the default
/// page (`1`), default size (`PAGINATION_DEFAULT_PAGE_SIZE`), and the
/// hard `page_size` clamp. Pulled into a free function so the same
/// resolution logic is unit-testable without spinning a router.
fn resolve_page_params(q: &PageQuery) -> (usize, usize) {
    let page = q.page.unwrap_or(1).max(1);
    let page_size = q
        .page_size
        .unwrap_or(PAGINATION_DEFAULT_PAGE_SIZE)
        .clamp(1, PAGINATION_MAX_PAGE_SIZE);
    (page, page_size)
}

/// Build the `pagination` envelope shared by `/v1/algorithms` and
/// `/v1/materializers`. `path` is the relative URL prefix (e.g.
/// `/v1/algorithms`) used to render `next_url` / `prev_url`. `extra`
/// is appended verbatim after `page=N&page_size=K` so callers can
/// preserve filters like `&summary=true` across pages.
fn pagination_envelope(
    page: usize,
    page_size: usize,
    total: usize,
    path: &str,
    extra: &str,
) -> JsonValue {
    let total_pages = total.div_ceil(page_size.max(1));
    let has_next = page < total_pages;
    let has_prev = page > 1 && total > 0;
    let url_for = |p: usize| -> String { format!("{path}?page={p}&page_size={page_size}{extra}") };
    json!({
        "page":       page,
        "page_size":  page_size,
        "total":      total,
        "total_pages": total_pages,
        "has_next":   has_next,
        "next_url":   if has_next { Some(url_for(page + 1)) } else { None },
        "has_prev":   has_prev,
        "prev_url":   if has_prev { Some(url_for(page - 1)) } else { None },
    })
}

/// Project one algorithm entry. When `summary == true`, drop `formula`
/// and `temporal_recipe` — the two heavy fields that pushed the full
/// registry response over MCP's 25 KB cap. The `key`, `kind`,
/// `input_bands`, and `citation` headline are always retained so an
/// agent can decide whether to GET `/v1/algorithms/<key>` for the full
/// body. Returns the structured-serde value when the entry can't be
/// projected (defensive — `Algorithm` always serializes, but we never
/// panic in a route handler).
fn project_algorithm_entry(a: &emem_core::algorithms::Algorithm, summary: bool) -> JsonValue {
    if !summary {
        return serde_json::to_value(a).unwrap_or(json!({}));
    }
    let inputs: Vec<&str> = a.inputs.iter().filter_map(|i| i.band.as_deref()).collect();
    json!({
        "key":           a.key,
        "kind":          a.kind,
        "domain":        a.domain,
        "inputs":        inputs,
        "output":        a.output,
        "citation":      a.citation,
        "when_to_use":   a.when_to_use,
        "fetch_url":     format!("/v1/algorithms/{}", a.key),
        "summary":       true,
    })
}

/// Project one entry of the `/v1/ask` `algorithms_for_question[]` list.
/// When `verbose == false` (the default since the 2026-05-05 deepscan)
/// drop the long `formula` body and the `temporal_recipe` block — both
/// live at `/v1/algorithms/<key>` so the agent can fetch them on
/// demand. The signed receipt itself is unrelated to this projection
/// and stays intact in `facts.facts[]`.
fn project_algorithm_for_question(
    topic: &str,
    a: &emem_core::algorithms::Algorithm,
    inputs: &[&str],
    verbose: bool,
) -> JsonValue {
    if verbose {
        json!({
            "topic":            topic,
            "key":              a.key,
            "kind":             a.kind,
            "input_bands":      inputs,
            "formula":          a.formula,
            "output":           a.output,
            "citation":         a.citation,
            "fetch_url":        format!("/v1/algorithms/{}", a.key),
            "temporal_recipe":  a.temporal_recipe,
        })
    } else {
        json!({
            "topic":            topic,
            "key":              a.key,
            "kind":             a.kind,
            "input_bands":      inputs,
            "output":           a.output,
            "citation":         a.citation,
            "fetch_url":        format!("/v1/algorithms/{}", a.key),
        })
    }
}

async fn algorithms(axum::extract::Query(q): axum::extract::Query<PageQuery>) -> Json<JsonValue> {
    let reg = &*emem_core::algorithms::DEFAULT;
    let cid = ALGORITHMS_CID.clone();
    let (page, page_size) = resolve_page_params(&q);
    let summary = q.summary.unwrap_or(false);

    let total = reg.algorithms.len();
    let start = (page - 1).saturating_mul(page_size).min(total);
    let end = start.saturating_add(page_size).min(total);
    let items: Vec<JsonValue> = reg.algorithms[start..end]
        .iter()
        .map(|a| project_algorithm_entry(a, summary))
        .collect();
    let extra = if summary { "&summary=true" } else { "" };
    let pagination = pagination_envelope(page, page_size, total, "/v1/algorithms", extra);

    Json(json!({
        "manifest": reg.manifest,
        "version":  reg.version,
        "algorithms_cid": cid,
        "_note": reg.note,
        "_explanation": "Paginated list — defaults to page=1, page_size=20 (max 100) so the response fits MCP's 25 KB cap. Pass `?page=N&page_size=K` to walk the registry, `?summary=true` to drop the long `formula` body and `temporal_recipe` per entry, or GET `/v1/algorithms/<key>` for one entry's full detail. `pagination.total` is the full registry size — agents MUST follow `pagination.next_url` to see the rest.",
        "agent_hint": {
            "what_this_is": "A content-addressed dictionary of recipes that combine attested band facts into composite answers (e.g. flood_risk@1, water_consensus@1, embedding_novelty@1). Receipts citing one of these names + the algorithm_cid let any other operator replay the same composition deterministically.",
            "how_to_use":    "1) Pick the entry whose `when_to_use` matches the agent's query. 2) Read its `inputs[].band` list and assemble a single `/v1/recall` (or `/v1/recall_many`) body. 3) Apply the `formula` in-process. 4) Cite the algorithm key + algorithms_cid alongside the fact_cids in the agent's reply.",
            "kinds": {
                "solo":      "single band → derived classification or scalar",
                "combined":  "multi-band weighted composite",
                "embedding": "cosine / novelty / change over geotessera vectors",
            },
        },
        "pagination": pagination,
        "items": items.clone(),
        // Back-compat alias. Older clients (and the homepage demo) still
        // read the top-level `algorithms` key. Keep it pointing at the
        // SAME paginated slice — never the full set — so the page-size
        // contract is honoured uniformly. Agents that want everything
        // must follow `pagination.next_url`.
        "algorithms": items,
    }))
}

/// `GET /v1/algorithms/:key` — one algorithm entry by key (URL-encode
/// the `@` in keys like `flood_risk@1` if your client cares — most
/// don't). Returns 404 if the key is unknown.
async fn algorithm_detail(
    axum::extract::Path(key): axum::extract::Path<String>,
) -> Result<Json<JsonValue>, ApiError> {
    let reg = &*emem_core::algorithms::DEFAULT;
    match reg.lookup(&key) {
        Some(a) => Ok(Json(serde_json::to_value(a).unwrap_or(json!({})))),
        None => {
            let known: Vec<&str> = reg.algorithms.iter().map(|a| a.key.as_str()).collect();
            Err(ApiError(
                StatusCode::NOT_FOUND,
                ErrorBody {
                    code: emem_core::error::ErrorCode::CidNotFound,
                    message: format!(
                        "no algorithm with key {key:?}; see /v1/algorithms — known keys: {}",
                        known.join(", "),
                    ),
                    details: None,
                },
            ))
        }
    }
}

/// Topic-grouped band + algorithm registry. Single source of truth for
/// the discovery surface that lives at `/v1/topics`, the
/// `data_at_this_cell` block in `/v1/locate`, and the MCP
/// `emem_topics` tool. Lifting it out of inline JSON literals
/// guarantees the three surfaces never drift.
///
/// Design contract: every band in `live_bands_by_topic` has a live
/// materializer at this responder; every algorithm in
/// `algorithms_for_topic` resolves in
/// `emem_core::algorithms::DEFAULT`. The
/// `declared_but_no_materializer_at_this_responder` block is the
/// honest "slot reserved, no connector" hint — agents should report
/// these as gaps rather than concluding the protocol can't answer.
fn topics_payload() -> JsonValue {
    // Drive the topic groupings from `topics-v0.json` (the content-addressed
    // registry under `topics_cid`) so /v1/topics surfaces every routable
    // topic instead of the partial inline subset the function originally
    // hardcoded. `live_bands_by_topic` keeps its old contract — only bands
    // the responder will actually materialise — by filtering each topic's
    // declared bands against `all_materializable_bands()`. Algorithms are
    // surfaced verbatim from the registry; the existing `topics_payload_
    // algorithm_keys_resolve_in_registry` test guards against drift between
    // topics-v0.json and algorithms-v0.json.
    let topic_reg = &*emem_core::topics::DEFAULT;
    let materializable: Vec<String> = all_materializable_bands();
    let live: std::collections::HashSet<&str> = materializable.iter().map(|s| s.as_str()).collect();
    let algo_reg = &*emem_core::algorithms::DEFAULT;
    let caps = cached_capabilities();
    let live_extensions: std::collections::HashSet<&str> =
        caps.extensions.iter().map(|s| s.as_str()).collect();

    let mut live_bands_by_topic = serde_json::Map::new();
    let mut algorithms_for_topic = serde_json::Map::new();
    // Capability overlay: for every algorithm key referenced by any
    // topic, declare whether it can run *right now* given the cached
    // sidecar capabilities. Uses the `inference.required_extension`
    // field on each algorithm — `None` means scalar/CPU and runs
    // unconditionally; `Some("gpu")` requires the sidecar to advertise
    // `gpu` in `extensions[]`. Surface as a map so agents can filter
    // their candidate list at planning time without hitting /health.
    let mut algorithm_availability = serde_json::Map::new();
    for t in &topic_reg.topics {
        let live_only: Vec<JsonValue> = t
            .bands
            .iter()
            .filter(|b| live.contains(b.as_str()))
            .cloned()
            .map(JsonValue::String)
            .collect();
        if !live_only.is_empty() {
            live_bands_by_topic.insert(t.key.clone(), JsonValue::Array(live_only));
        }
        if !t.algorithms.is_empty() {
            algorithms_for_topic.insert(
                t.key.clone(),
                JsonValue::Array(
                    t.algorithms
                        .iter()
                        .cloned()
                        .map(JsonValue::String)
                        .collect(),
                ),
            );
            for k in &t.algorithms {
                if algorithm_availability.contains_key(k) {
                    continue;
                }
                let required = algo_reg
                    .lookup(k)
                    .and_then(|a| a.inference.as_ref())
                    .and_then(|i| i.required_extension.as_deref());
                let available_now = required
                    .map(|ext| live_extensions.contains(ext))
                    .unwrap_or(true);
                algorithm_availability.insert(
                    k.clone(),
                    json!({
                        "available_now": available_now,
                        "required_extension": required,
                    }),
                );
            }
        }
    }

    json!({
        "_purpose": "Topic-grouped list of every band you can recall at this cell, plus the algorithm recipes that compose those bands into named scores. Read this BEFORE concluding the responder doesn't have data on a topic, and BEFORE inventing a synthesis formula in your own reasoning.",
        "_source": format!(
            "Driven from the content-addressed topic registry (topics-v0.json, {} topics). `live_bands_by_topic` filters each topic's declared bands against this responder's wired materializers; `algorithms_for_topic` is verbatim from the registry. Topics absent from `live_bands_by_topic` have all their bands declared-but-not-wired here — see `declared_but_no_materializer_at_this_responder`.",
            topic_reg.topics.len()
        ),
        "_pointer_to_algorithms": format!(
            "GET /v1/algorithms for the full content-addressed registry of {} composition recipes (flood_risk, walkability, embedding_novelty, carbon-MRV, SDG indicators, etc.) used by `algorithms_for_topic` below. Cite the algorithm key + algorithms_cid in the receipt.",
            emem_core::algorithms::DEFAULT.algorithms.len()
        ),
        "live_bands_by_topic": live_bands_by_topic,
        "algorithms_for_topic": algorithms_for_topic,
        "algorithm_availability": algorithm_availability,
        "_capabilities_hint": "GET /v1/capabilities for the live extensions[] snapshot. \
                                `algorithm_availability[<key>].available_now == false` means \
                                the algorithm's `inference.required_extension` is not in the \
                                sidecar's current extensions[] (typically GPU off / sidecar down). \
                                Use a CPU/scalar alternative for the same topic, or surface an \
                                honest `gpu_unavailable` to the user.",
        "visual_surfaces": {
            "rgb_scene_png": "GET /v1/cells/{cell64}/scene.png?max_cloud=20  (or MCP `emem_cell_scene_rgb`) — true-colour Sentinel-2 L2A 256×256 thumbnail",
            "cell_geojson":  "GET /v1/cells/{cell64}/geojson — polygon hexagon for any GIS / map renderer",
            "cell_recall_geojson": "GET /v1/cells/{cell64}/recall_geojson?bands=... — properties carry every fact value the responder has, ready to style",
        },
        "declared_but_no_materializer_at_this_responder": {
            "_meaning": "Bands reserved in the cube manifest but with no live connector at this responder. Recall returns empty (existing attestations only, no upstream fetch).",
            "_authoritative_list": "GET /v1/bands — every band entry now carries a `materializer:{kind:'live'|'declared_no_connector', ...}` field. Filter on kind=='declared_no_connector' for the canonical, code-derived set.",
            "_note_on_cube_family_roots": "Most unwired keys are cube FAMILY-ROOT slots whose SCALAR children are wired (e.g. `koppen` root unwired but `koppen.major_class` live; `surface_water` cube key reserved but `surface_water.recurrence` answers the flood-history question). Use /v1/materializers for the per-scalar wired list.",
            "_note_on_foundation_models_at_this_responder": "Three foundation embeddings are wired at this responder. `geotessera` (Tessera v1, 128-D, 10 m grid, annual) is the default similarity surface. `prithvi_eo2` (IBM-NASA Prithvi-EO-2.0-300M-TL, 1024-D fact value carried in the 384-D cube slot at offset 894, 30 m chip / 6.7 km receptive field, scene-aware) anchors algorithms that need a learned ViT representation rather than a contrastive embedding. `galileo_base` (off-cube; surfaced via the sidecar's /predict/galileo_embed) is the Galileo Base 768-D foundation embedding for S2-only chips. Clay Foundation Model is on the roadmap and not yet wired — when it lands, the cube will reshape to add a `clay_v1` slot.",
        },
        "how_to_use": "Pick the topic that matches the user's question. (1) If the user wants ONE band's value, look up `live_bands_by_topic` and call `emem_recall` with those bands — they auto-fetch on miss. (2) If the user wants a COMPOSITE answer (flood risk, walkability, climate exposure, similarity, change), look up `algorithms_for_topic` and call `emem_algorithms` for the recipe — apply its `formula` over a single `emem_recall` body that fetches every input band, then cite the algorithm key + algorithms_cid alongside the input fact_cids. (3) For a VISUAL answer, hit `visual_surfaces.rgb_scene_png` (or MCP `emem_cell_scene_rgb`). (4) If the topic only appears under `declared_but_no_materializer_at_this_responder`, tell the user this responder has the slot reserved but no live connector (don't claim emem has no flood/water/etc. data — be precise). Topics not listed at all (e.g. real-time air quality, traffic) are genuinely out of scope for this protocol today.",
        "for_temporal_questions": "For 'last N years' questions, materializers return one fact at the latest available tslot. To get a series, call `emem_recall` repeatedly for past tslots only if the band's tempo is `slow`/`static` (which means one fact covers the period). For `fast`/`medium` tempo bands, history requires the responder to have already seeded past tslots — call `emem_trajectory` to enumerate what's there, do NOT assume historical lookback materializes on demand.",
    })
}

/// `GET /v1/topics` — content-addressed topic registry exposed as a
/// first-class endpoint. Same body the `/v1/locate` `data_at_this_cell`
/// block returns; broken out so an agent can browse the topic
/// inventory without having to first locate a cell.
async fn topics() -> Json<JsonValue> {
    Json(json!({
        "schema": "emem.topics.v1",
        "topics": topics_payload(),
    }))
}

/// `GET /v1/errors` — error catalogue with action hints. Just listing the
/// codes (which is what we did before) doesn't tell an agent what to DO
/// when it hits one. Each entry now has a `recover` field naming the
/// concrete next step.
fn errors_payload() -> JsonValue {
    let entries: &[(&str, &str, &str)] = &[
        ("invalid_cell",                 "cell64 string did not parse",
         "Re-encode (lat,lng) via POST /v1/locate, or check the bigram boundaries (must be exactly four base-1024 bigrams joined by '.')."),
        ("invalid_resolution",           "resolution bits out of range",
         "Use the cell64 returned by /v1/locate; that's always at the active resolution. See /v1/grid_info."),
        ("tslot_mismatch",               "tslot in request doesn't match band's expected tempo",
         "Check /v1/bands for the band's `tempo` field and round your tslot to that grid."),
        ("band_not_in_registry",         "band key isn't in the active manifest",
         "GET /v1/bands for the canonical list. Common typos: missing schema namespace (need `copdem30m.elevation_mean`, not `elevation_mean`)."),
        ("function_not_in_registry",     "derivation fn_key not registered",
         "Functions ship via /v1/functions. To use a private function, register it in your registry_cid before attesting."),
        ("source_scheme_unknown",        "source.scheme not in /v1/sources",
         "GET /v1/sources for the active connector list. Self-hosters can add via the source manifest."),
        ("cid_not_found",                "fact CID exists but no matching object on disk",
         "The fact may have been pruned, or the CID is from a different responder. Verify `responder_pubkey_b32` matches between the receipt and /health."),
        ("no_geocoder_match",            "place name did not resolve in any geocoder tier (Photon + Nominatim both said 'no such place')",
         "Refine the query (more specific name; add country / region / admin level), pass `lat`+`lng` coordinates directly, or call POST /v1/locate first to inspect alternatives."),
        ("place_not_found",              "all upstream geocoders responded successfully but unanimously returned zero results — the place name is genuinely not in any layer of the cascade (embedded gazetteer, cache, Photon, Nominatim). Distinct from `geocoder_transport_down`, which means the upstream HTTP/JSON layer itself failed.",
         "Refine the query: add country/region disambiguation (e.g. 'Springfield, IL, USA'), use the official local-language spelling, or pass `lat`+`lng` directly. /v1/locate's response surfaces `via` so an agent can see which tier rejected the query."),
        ("geocoder_transport_down",      "the upstream geocoder transport failed (HTTP 5xx, DNS, timeout, malformed JSON) before a real not-found verdict could be issued. Distinct from `place_not_found` (transports succeeded but returned zero results) and from `no_geocoder_match` (the legacy code that conflated both — kept for backwards compatibility).",
         "Retry with backoff (Photon and Nominatim are public services and occasionally rate-limit). If persistent, pass `lat`+`lng` directly to bypass the geocoder. Operators can switch the primary geocoder via env."),
        ("invalid_argument",             "syntactically valid but semantically invalid request field (e.g. unparseable timestamp, out-of-range numeric, malformed enum)",
         "Re-read /openapi.json for the field's accepted shape. Common causes: ISO 8601 missing 'Z' for UTC; max_cells > 1024; band key with wrong namespace prefix."),
        ("registry_cid_unknown",         "the bound registry_cid isn't recognised",
         "Receipts pin manifest CIDs at issue time; if the responder rotated manifests, check /v1/manifests for the current `registry_cid`."),
        ("schema_cid_unknown",           "fact's schema_cid isn't loaded",
         "GET /v1/manifests for the current `schema_cid`. Re-attest with the active schema, or pin the older manifest if the responder still has it."),
        ("privacy_refused",              "band's privacy_class blocks this query at the requested resolution",
         "Drop the resolution (snap to a coarser cell) or request via an authorised attester. Check /v1/bands for `privacy_class`."),
        ("level_too_low",                "operation requires a higher protocol level (L1/L2)",
         "L0/L1 are anonymous; L2 (write/challenge) requires an attester key. Generate ed25519, post to /v1/attest_cbor."),
        ("attester_revoked",             "the attester pubkey is in the revocation set",
         "Check /v1/contributors for `revoked` flag. Submit a fresh keypair if revoked legitimately, or contest via /v1/challenge."),
        ("unauthorized",                 "missing or invalid attester signature on a write",
         "Re-sign with the same keypair that issued the registered attester pubkey; signature must be over blake3(batch_root || registry_cid || schema_cid)."),
        ("claim_undecidable",            "verify input doesn't yield true/false (e.g. NaN, type mismatch)",
         "Inspect the fact via /v1/recall — the value may be missing, the wrong type, or NaN. Tighten your claim or pre-filter before /v1/verify."),
        ("bad_signature",                "ed25519 signature failed to verify",
         "Re-sign with the correct preimage. /v1/verify_receipt's response includes `preimage_blake3_hex` so you can debug locally."),
        ("bad_merkle_proof",             "Merkle inclusion proof is malformed or doesn't reach the batch_root",
         "Re-build the proof from the canonical-sorted leaf list; verify `leaf_index` is correct."),
        ("canonical_encoding_divergence","CBOR you sent isn't deterministic per RFC 8949 §4.2.1",
         "Use a CBOR library with `canonical=true`; serde-derived structs are usually fine, freeform maps must have sorted keys."),
        ("source_fetch_failed",          "upstream open-data provider returned non-2xx",
         "Retry with backoff; check /v1/sources to confirm the URL template still resolves. May indicate provider-side outage."),
        ("source_format_mismatch",       "fetched bytes don't match the declared scheme (e.g. GeoTIFF magic missing)",
         "Re-fetch with explicit content-type. Could indicate provider migrated to a new format; consult their docs."),
        ("compute_timeout",              "derivation function exceeded EMEM_TIMEOUT_SECS",
         "Submit smaller inputs, or run the computation client-side and attest the derivative directly."),
        ("compute_quota_exceeded",       "function call hit per-attester quota",
         "Throttle, or request quota increase via /v1/contributors leaderboard (high-score attesters get larger quotas)."),
        ("rate_limited",                 "per-IP rate limit hit",
         "Backoff per the `Retry-After` header (default 60 s). Operators tune via EMEM_RATE_LIMIT_RPS."),
        ("cache_error",                  "responder's hot cache (sled) had an internal error",
         "Retry; if persistent, the responder's storage may need recovery — operators see the cause in the journald log."),
        ("internal",                     "responder-side bug",
         "Capture the response and the request that produced it; file at https://github.com/Vortx-AI/emem/issues."),
    ];
    let codes: Vec<JsonValue> = entries
        .iter()
        .map(|(c, m, r)| {
            json!({
                "code": c, "meaning": m, "recover": r,
            })
        })
        .collect();
    json!({
        "schema": "emem.errors.v1",
        "codes": codes,
        "next": [
            "GET /v1/manifests  — current registry/schema/bands/sources CIDs",
            "GET /v1/bands      — band catalogue with tempo + privacy_class",
            "POST /v1/verify_receipt — debug a bad_signature with `preimage_blake3_hex`"
        ],
    })
}

async fn errors() -> Json<JsonValue> {
    Json(errors_payload())
}

async fn tools() -> Json<JsonValue> {
    let descriptors: Vec<JsonValue> = emem_mcp::TOOLS.iter().map(|t| json!({
        "name": t.name,
        "title": t.title,
        "description": t.description,
        "when_to_use": t.when_to_use,
        "input_schema": serde_json::from_str::<JsonValue>(t.input_schema).unwrap_or(json!({})),
        "example_args": serde_json::from_str::<JsonValue>(t.example_args).unwrap_or(json!({})),
        "level": t.level,
        "category": t.category,
        "annotations": {
            "title":           t.title,
            "readOnlyHint":    t.read_only_hint,
            "destructiveHint": t.destructive_hint,
            "idempotentHint":  t.idempotent_hint,
            "openWorldHint":   t.open_world_hint,
        },
    })).collect();
    Json(json!({ "tools": descriptors }))
}

async fn agent_card(State(s): State<AppState>) -> Json<JsonValue> {
    let descriptors: Vec<JsonValue> = emem_mcp::TOOLS.iter().map(|t| json!({
        "name": t.name,
        "title": t.title,
        "description": t.description,
        "when_to_use": t.when_to_use,
        "level": t.level,
        "category": t.category,
        "input_schema": serde_json::from_str::<JsonValue>(t.input_schema).unwrap_or(json!({})),
        "example_args": serde_json::from_str::<JsonValue>(t.example_args).unwrap_or(json!({})),
        "annotations": {
            "title":           t.title,
            "readOnlyHint":    t.read_only_hint,
            "destructiveHint": t.destructive_hint,
            "idempotentHint":  t.idempotent_hint,
            "openWorldHint":   t.open_world_hint,
        },
    })).collect();
    Json(json!({
        "name": "emem",
        "version": env!("CARGO_PKG_VERSION"),
        "purpose": "Agent-native, content-addressed memory of every place on Earth. Cite-able answers about places, signed receipts, token-economical addressing.",
        "trigger_phrases": [
            "what is at <place>",
            "tell me about this cell",
            "compare X and Y",
            "find places like X",
            "did <band> change between t1 and t2",
            "is <claim> true at <place>",
            "average <band> over this region"
        ],
        "primary_tools": ["emem_recall", "emem_compare", "emem_find_similar", "emem_diff", "emem_verify"],
        // Order matters: bands → materializers → coverage_matrix builds
        // the agent's mental model in the right order. Bands declare
        // what *can* exist; materializers declare what auto-fetches on
        // recall miss (so the agent knows it can recall any cell on
        // Earth without seeding); coverage_matrix declares what's
        // already cached + freshness. Manifests pin the CIDs for
        // citation. Without `emem_materializers` here, agents miss the
        // auto-materialize contract and assume empty recall = no data.
        "discover_first": ["emem_bands", "emem_materializers", "emem_algorithms", "emem_coverage_matrix", "emem_manifests"],
        "authentication": "none for L0/L1; ed25519 attester for L2 writes",
        // Required by the Anthropic Software Directory submission flow:
        // every connector must expose a privacy URL, a terms URL, and a
        // support contact. These point to the markdown docs served from
        // /privacy and /terms; vendor + contact email are explicit so the
        // reviewer can reach the maintainer without scraping the repo.
        "vendor": "Vortx-AI",
        "contact_email": "avijeet@vortx.ai",
        // Path-relative so a self-hosted operator on a different origin
        // doesn't publish broken external links. Mirrors the same shape
        // already used at /.well-known/emem.json.
        "privacy_url": "/privacy",
        "terms_url": "/terms",
        "support_url": "https://github.com/Vortx-AI/emem/issues",
        "documentation_url": "https://github.com/Vortx-AI/emem#readme",
        "license": "Apache-2.0",
        "license_url": "https://github.com/Vortx-AI/emem/blob/main/LICENSE",
        "responder": {
            "pubkey_b32": data_encoding::BASE32_NOPAD.encode(&s.identity.pubkey.0).to_lowercase(),
            "key_epoch": s.identity.epoch.0,
        },
        "manifests": {
            "bands_cid": &s.manifests.bands_cid,
            // Spec key. `functions_cid` is the legacy alias for the same
            // value; both are set so clients diffing by either key see
            // a match. New code should read `registry_cid`.
            "registry_cid": s.manifests.registry_cid.as_str(),
            "functions_cid": s.manifests.registry_cid.as_str(),
            "sources_cid": &s.manifests.sources_cid,
            "schema_cid": s.manifests.schema_cid.as_str(),
            "algorithms_cid": ALGORITHMS_CID.clone(),
            "topics_cid": TOPICS_CID.clone(),
            // Which routing backend the topic_router actually loaded at
            // startup. "transformer" = model2vec-rs cosine match (the
            // happy path); "keyword" = alias-keyword fallback because
            // the model could not be fetched / loaded. Surfaced so an
            // agent debugging routing quality can tell at a glance
            // whether the responder is in degraded mode.
            "topic_router_backend": topic_router::TopicRouter::global().backend_name(),
        },
        // Reconciles the four band counts agents see across surfaces so
        // they don't have to guess which one is authoritative. The
        // numbers come from one place each — no copy / no constant —
        // so this stays in sync as connectors land or retire.
        "band_taxonomy": {
            "_purpose": "Four different band counts surface across the protocol because they measure different things. This block names each one and gives the live count from the same source the corresponding endpoint reads, so an agent sees a unified picture.",
            "cube_slots": {
                "count":          emem_core::bands::DEFAULT.bands.len(),
                "what_it_means":  "Top-level band keys in the canonical 1792-D voxel layout (geotessera, sentinel2_raw, indices, etc.). One slot can carry many attestable subkeys (e.g. sentinel2_raw covers s2.B01..B12).",
                "see_endpoint":   "/v1/bands",
            },
            "materializer_wired": {
                "count":          all_materializable_bands().len(),
                "what_it_means":  "Concrete band names (cube slot + subkey) that this responder will auto-fetch on a recall miss. Every entry maps to a real upstream connector.",
                "see_endpoint":   "/v1/materializers (also /v1/data_availability with kind/tempo/history-window per band)",
            },
            "tools": {
                "count":          emem_mcp::TOOLS.len(),
                "what_it_means":  "Distinct MCP / REST tools — what an agent actually calls. Some tools cross many bands (e.g. emem_recall is one tool that recalls any wired band).",
                "see_endpoint":   "/v1/tools (or MCP tools/list)",
            },
            "algorithms": {
                "count":          emem_core::algorithms::DEFAULT.algorithms.len(),
                "what_it_means":  "Composition recipes that fuse multiple band facts into named scores (flood_risk, walkability, carbon NPP, SDG indicators, …). Each is content-addressed under algorithms_cid.",
                "see_endpoint":   "/v1/algorithms",
            },
        },
        "surfaces": {
            "rest_openapi":     "/openapi.json",
            "rest_openapi_action_subset": "/v1/openapi.action.json",
            "mcp_jsonrpc":      "/mcp",
            "well_known":       "/.well-known/emem.json",
            "ai_plugin":        "/.well-known/ai-plugin.json",
            "agents_md":        "/agents.md",
            "whitepaper_md":    "/whitepaper.md",
            "llms_txt":         "/llms.txt",
            "privacy":          "/privacy",
            "terms":            "/terms",
            "fleet":            "/v1/fleet",
            "coverage_matrix":  "/v1/coverage_matrix",
            "materializers":    "/v1/materializers",
            "data_availability":"/v1/data_availability",
            "algorithms":       "/v1/algorithms",
            "temporal_route":   "/v1/temporal_route",
            "reviews":          "/v1/reviews",
        },
        // Honest declaration of which non-JSON surfaces exist and which
        // protocol channels actually expose them. The infrastructure
        // pre-dates wide MCP image-block support, so today: SVG/GeoJSON
        // are reachable via REST but get text-wrapped by MCP. Documented
        // here so agents discover the gap rather than assuming emem
        // doesn't ship multimodal at all.
        "multimodal_surfaces": {
            "_status_summary": "REST DELIVERS images (image/svg+xml + image/png) and geo+json today. MCP delivers the coverage map as a native EmbeddedResource via `emem_coverage_map`, per-cell true-colour Sentinel-2 thumbnails as native ImageContent via `emem_cell_scene_rgb`, and cell polygons as native EmbeddedResource (geo+json) via `emem_cell_geojson`. INGESTION is JSON/CBOR only — no image upload or binary-vector-as-payload endpoint yet.",
            "deliver": {
                "coverage_map_svg": {
                    "url": "/v1/coverage_map.svg",
                    "mime": "image/svg+xml",
                    "wired_via": "REST + MCP",
                    "mcp_tool": "emem_coverage_map",
                    "mcp_content_block": "EmbeddedResource (text resource, mimeType image/svg+xml) + a text summary block",
                    "agent_use":  "Multimodal MCP agents call `emem_coverage_map` and receive a native EmbeddedResource block. Plain REST callers GET /v1/coverage_map.svg and receive the bare 1440×720 Plate-Carrée SVG. Both paths share the same renderer."
                },
                "cell_geojson": {
                    "url_template": "/v1/cells/{cell64}/geojson",
                    "mime": "application/geo+json",
                    "wired_via": "REST + MCP",
                    "mcp_tool": "emem_cell_geojson",
                    "mcp_content_block": "EmbeddedResource (text resource, mimeType application/geo+json) + a text summary block",
                    "agent_use":  "Polygon (4-vertex rectangle on the active ~10 m square cell64 grid; the spec target is a 3.4 m H3 hex but that grid is not yet active — surface this in the receipt's caveats) + bbox / centre lat,lng / neighbours. Drop straight into Mapbox/Leaflet/Deck.gl/QGIS without a GIS pipeline."
                },
                "cell_scene_rgb": {
                    "url_template": "/v1/cells/{cell64}/scene.png?max_cloud=20",
                    "mime": "image/png",
                    "wired_via": "REST + MCP",
                    "mcp_tool": "emem_cell_scene_rgb",
                    "mcp_content_block": "ImageContent (base64 PNG, mimeType image/png) + a text summary block with the STAC item id / capture time / stretch values",
                    "agent_use":  "True-colour Sentinel-2 L2A thumbnail centred on the cell, 256×256 px (~2.56 km × ~2.56 km at S2's 10 m native). Auto-picks the latest scene with `eo:cloud_cover < max_cloud` (default 20 %, override via query/arg). Pure-Rust pipeline — STAC search + HTTPS-Range COG reads + 2-98 percentile stretch + PNG encode. The STAC item id is emitted in `x-emem-scene-item-id` header (REST) and structuredContent (MCP) so the receipt is reproducible."
                },
                "cell_recall_geojson": {
                    "url_template": "/v1/cells/{cell64}/recall.geojson?bands={bands}",
                    "mime": "application/geo+json",
                    "wired_via": "REST",
                    "mcp_wrapped_as": "text",
                    "agent_use":  "Polygon properties carry every fact value the responder has at the cell — one call to render a styled choropleth."
                },
                "embedding_vectors": {
                    "transport": "JSON arrays inside Fact.value",
                    "wired_via": "REST + MCP",
                    "agent_use":  "Geotessera 128-D and multi_year 1024-D vectors travel as JSON-encoded float arrays inside the standard recall envelope (decoded from upstream int8+scale). There is no separate binary / Arrow / msgpack vector channel today."
                }
            },
            "ingest": {
                "_state": "no image / vector ingestion path is wired today",
                "attestations": {
                    "url": "/v1/attest_cbor",
                    "mime": "application/cbor",
                    "carries": "PrimaryFact / DerivativeFact / Absence as canonical CBOR — structured fact data, NOT image bytes. Submit ed25519-signed batches to grow the corpus."
                },
                "image_input_for_similarity": {
                    "status": "not_wired",
                    "note":   "There is no /v1/find_similar_image (or equivalent multipart upload) for 'find places that look like this satellite preview'. Workaround today: have the agent map the image to a known cell64 (e.g. by user-supplied location), then /v1/find_similar over `geotessera`."
                },
                "vector_payload_input": {
                    "status": "supported_via_inline_literal",
                    "note":   "/v1/find_similar accepts `key: \"inline:[v0,v1,...]\"` — a JSON-array literal. There is no binary fp16 ingestion path."
                }
            },
            "what_to_build_next": [
                "MCP `emem_coverage_map` tool that returns the SVG as a `resource` content block with mime + text — so multimodal MCP agents see the image natively.",
                "Server-side SVG → PNG raster (resvg crate) so Anthropic / OpenAI image-input clients can ingest the coverage map.",
                "/v1/find_similar_image — multipart upload → geotessera lookup via a small image encoder (Tessera v1 has a published encoder).",
                "Binary vector channel: application/octet-stream fp16 for k-NN payloads (saves ~6× over JSON arrays for the 1024-D multi_year vector)."
            ]
        },
        // Curated signposts grouped by use-case so agents skimming the
        // card can see at a glance which family of question maps to
        // which band(s). Only WIRED materializers appear here — empty
        // groups are omitted rather than stubbed. For the canonical
        // per-band roster (with upstream URLs and absence semantics),
        // call `emem_materializers`; for live counts and freshness
        // call `emem_coverage_matrix`.
        "live_bands": {
            "vegetation_fast":      ["indices.ndvi","indices.evi","indices.savi","indices.ndmi"],
            "vegetation_medium":    ["modis.ndvi_mean"],
            "water_history_long":   ["surface_water.recurrence"],
            "water_event_window":   ["indices.ndwi","indices.mndwi"],
            "fire_burn_scar":       ["indices.nbr"],
            "soil_bare":            ["indices.bsi"],
            "built_up":             ["indices.ndbi","overture.buildings.count","overture.places.count","overture.transportation.road_length_m"],
            "weather_15min":        ["weather.temperature_2m","weather.cloud_cover","weather.precipitation_mm","weather.wind_speed_10m"],
            "elevation_global":     ["gmrt.topobathy_mean"],
            "elevation_land_only":  ["copdem30m.elevation_mean"],
            "optical_raw":          ["s2.B02","s2.B03","s2.B04","s2.B08","s2.B11","s2.B12"],
            "scene_classification": ["s2.scl"],
            "foundation_embedding": ["geotessera","geotessera.multi_year","geotessera.bin128"],
        },
        "live_bands_discovery_hint": "live_bands is a curated subset; call `emem_materializers` for the full registry with upstream URLs, licenses, and value-kind (primary | absence | primary_or_absence). Call `emem_coverage_matrix` for per-band facts_count and last-attested timestamps.",
        "runtime": {
            "language":       "Rust",
            "no_python_at_request_path": true,
            "cog_reader":     "pure-Rust HTTPS-range TIFF/IFD parser + Deflate + Predictor 2 (no GDAL, no rasterio)",
            "weather_source": "MET Norway api.met.no (no API key, no per-IP rate limit)",
            "stac_search":    "Element84 earth-search (anonymous; AWS Open Data backed)",
            "gateway_timeout_secs":      timeout_seconds(),
            "materializer_timeout_secs": materializer_timeout_secs(),
            "client_timeout_advice":     "Set your HTTP client read timeout to gateway_timeout_secs + 5 s. /v1/ask on a cold cell can fan out 8–24 parallel materialisations whose worst-case is bounded by materializer_timeout_secs; /v1/recall and /v1/locate complete in <2 s when warm. If you need a hard upper bound, request `cell` + a single concrete `band` to skip the temporal_recipe expansion.",
        },
        "tools": descriptors,
    }))
}

async fn quickstart() -> Json<JsonValue> {
    Json(json!({
        "schema": "emem.quickstart.v1",
        "purpose": "Six-call flow proving agent integration: discover → fleet/coverage → locate → recall (multi-band) → audit → contribute.",
        "steps": [
            {
                "n": 1,
                "name": "Discover the surface",
                "method": "GET",
                "path": "/v1/discover",
                "why": "One call returns the agent_card, manifest CIDs, primary tools, canonical_places list, and next_call hints. Cheaper than reading the spec."
            },
            {
                "n": 2,
                "name": "Pick a band",
                "method": "GET",
                "path": "/v1/coverage_matrix",
                "why": "Per-band live status: which materializers are wired, how many facts are cached, when the band was last attested. Combine with /v1/fleet to map bands → satellites and /v1/temporal_route for cadence-aware ranking."
            },
            {
                "n": 3,
                "name": "Locate a place",
                "method": "POST",
                "path": "/v1/locate",
                "body": { "place": "Mount Fuji" },
                "expect": "200 with { cell64, neighborhood_cells (9), polygon_bbox?, polygon_sample_cells?, agent_hint, advice, via }. `via` declares whether the centroid came from the embedded gazetteer, the cache, or live Nominatim."
            },
            {
                "n": 4,
                "name": "Recall — fan out across bands and the neighborhood",
                "method": "POST",
                "path": "/v1/recall_many",
                "body": { "cells": ["defi.zb592.nemu.zEvE","defi.zb545.wAmA.zb9dd"], "bands": ["indices.ndvi","weather.temperature_2m","copdem30m.elevation_mean","geotessera"] },
                "expect": "200 with { by_cell: {<cell>: {facts, receipt, bands_already_attested_at_cell?}} }. NDVI from Sentinel-2 L2A via pure-Rust COG range read; weather from MET Norway (no API key); foundation embedding from Tessera v1; elevation from Cop-DEM."
            },
            {
                "n": 5,
                "name": "Audit one of the receipts offline",
                "method": "POST",
                "path": "/v1/verify_receipt",
                "body": { "receipt": "<paste any per-cell receipt object from step 4>" },
                "expect": "200 with { valid: true, signer_pubkey_b32, preimage_blake3_hex }. Anyone with the responder pubkey can recompute the preimage; this is what makes the answer cite-able."
            },
            {
                "n": 6,
                "name": "Contribute (optional)",
                "method": "POST",
                "path": "/v1/attest_cbor",
                "body": "<canonical CBOR Attestation>",
                "expect": "200 on accept. Generate ed25519, build canonical CBOR over PrimaryFact(s), Merkle-root the leaves, sign blake3(batch_root||registry_cid||schema_cid). See crates/emem-cli/src/bin/emem-realdemo.rs for a full Rust example. Increases your score on /v1/contributors."
            }
        ],
        "example_chat_to_paste_into_a_system_prompt":
            "When the user asks about a place (lat/lng, region name, or cell64), call emem.recall first via the cell64 returned by emem.locate's neighborhood_cells. Cite the response receipt's fact_cids (truncated cid64 form) in your reply. If the user asks 'what changed', use emem.diff. If 'find similar', use emem.find_similar.",
        "see_also": {
            "agent_walkthroughs":   "/examples/agent-walkthroughs.md",
            "errors_with_recovery": "/v1/errors",
            "grid_resolution":      "/v1/grid_info",
            "coverage_map_visual":  "/v1/coverage_map.svg"
        }
    }))
}

// ── Primitive routes ─────────────────────────────────────────────────────

/// Recall + lazy materialization. If the cache miss and the agent asked
/// for specific bands, fall through to the registered upstream connector,
/// sign the resulting fact under the responder identity, persist it, and
/// re-query.
///
/// Used by both `POST /v1/recall` and `POST /v1/recall_polygon` so the
/// fan-out path picks up the same auto-materialize behaviour as the
/// single-cell path. Without this shared helper, recall_polygon would
/// return zero facts at any cell that hasn't been seeded yet — defeating
/// the whole point of the polygon fan-out (which exists to fix
/// place-name drift, not to expose a different read shape).
/// Wrapper around the `find_similar` primitive that, on `CidNotFound`
/// for the requested vector band, attempts to materialize the band on
/// the query cell and retries. Returns the response plus a list of
/// `materialize_notes` (one per band touched) so the agent can see
/// what the responder fetched on its behalf.
///
/// Inline-vector queries (`key: "inline:[...]"`) carry their own vector
/// and never need materialization — they bypass this wrapper's retry
/// logic. Auto-materialize must be enabled at the responder
/// (`EMEM_AUTO_MATERIALIZE`) for any work to happen; otherwise this is a
/// thin pass-through.
///
/// bin128 is a special case: when the requested band is
/// `geotessera.bin128` (or any binary-sibling band) and the cell has a
/// cached geotessera vintage, `materialize_geotessera_bin128` derives
/// the binary band on the fly (sign-bit per dim of the TurboQuant
/// rotation, no upstream fetch). The cost is microseconds.
async fn find_similar_with_auto_materialize(
    req: &FindSimilarReq,
    band_used: &str,
    s: &AppState,
) -> Result<(emem_primitives::find_similar::FindSimilarResp, Vec<JsonValue>), ApiError> {
    let mut maybe_resp = find_similar(req, s).await;
    let mut materialize_notes: Vec<JsonValue> = Vec::new();
    if let Err(StorageError::Protocol {
        code: ErrorCode::CidNotFound,
        ..
    }) = &maybe_resp
    {
        if !req.key.starts_with("inline:") && auto_materialize_enabled() {
            let band_owned = band_used.to_string();
            let outcomes =
                try_materialize_bands(&req.key, std::slice::from_ref(&band_owned), s).await;
            let materialized_any = outcomes.iter().any(|o| o.fact_cid.is_some());
            for o in &outcomes {
                if let Some(cid) = &o.fact_cid {
                    materialize_notes.push(json!({
                        "band":     o.band,
                        "status":   "materialized",
                        "fact_cid": cid,
                    }));
                } else if let Some(reason) = &o.skip_reason {
                    materialize_notes.push(json!({
                        "band":   o.band,
                        "status": "skipped",
                        "reason": reason,
                    }));
                }
            }
            if materialized_any {
                maybe_resp = find_similar(req, s).await;
            }
        }
    }
    let resp = maybe_resp?;
    Ok((resp, materialize_notes))
}

async fn recall_with_auto_materialize(
    req: &RecallReq,
    s: &AppState,
) -> Result<(RecallResp, Vec<JsonValue>), ApiError> {
    use std::collections::HashSet;
    let mut resp = recall(req, s).await?;
    let mut materialize_notes: Vec<JsonValue> = Vec::new();

    // Per-band, on-demand materialization. The corpus grows as agents
    // demand: every (cell, band) the agent reaches for that we know how
    // to fetch is materialized, signed under the responder identity,
    // persisted, and then returned in the same response.
    //
    // Three cases drive what we try to materialize:
    //
    // (1) Request specifies bands: every band missing from the response
    //     is candidate. Lets an agent ask for [elevation, NDVI] and get
    //     both, even if NDVI was never seen at this cell before.
    // (2) Request specifies no bands AND cell is empty: materialize a
    //     small cheap default set (elevation + current temperature) so
    //     a bare `recall {"cell":"…"}` surfaces *something* instead of
    //     an empty array.
    // (3) Request specifies no bands AND cell has facts: leave alone.
    //     The agent didn't ask for anything new; don't pay an upstream
    //     fetch on every recall.
    let owned_default: Vec<String>;
    let candidates: &[String] = match req.bands.as_ref() {
        Some(req_bands) if !req_bands.is_empty() => {
            let present: HashSet<&str> = resp
                .facts
                .iter()
                .filter_map(|f| match f {
                    emem_fact::Fact::Primary(p) => Some(p.band.as_str()),
                    _ => None,
                })
                .collect();
            owned_default = req_bands
                .iter()
                .filter(|b| !present.contains(b.as_str()))
                .cloned()
                .collect();
            owned_default.as_slice()
        }
        _ if resp.facts.is_empty() => {
            owned_default = vec![
                "copdem30m.elevation_mean".into(),
                "weather.temperature_2m".into(),
            ];
            owned_default.as_slice()
        }
        _ => &[],
    };

    if !candidates.is_empty() {
        let outcomes = try_materialize_bands(&req.cell, candidates, s).await;
        let materialized_any = outcomes.iter().any(|o| o.fact_cid.is_some());
        for o in &outcomes {
            if let Some(reason) = &o.skip_reason {
                materialize_notes.push(json!({
                    "band":   o.band,
                    "status": "skipped",
                    "reason": reason,
                }));
            } else if o.fact_cid.is_some() {
                materialize_notes.push(json!({
                    "band":   o.band,
                    "status": "materialized",
                    "fact_cid": o.fact_cid.as_deref(),
                }));
            }
        }
        if materialized_any {
            resp = recall(req, s).await?;
        }
    }
    Ok((resp, materialize_notes))
}

async fn get_cell(
    State(s): State<AppState>,
    Path(cell64): Path<String>,
) -> Result<Json<JsonValue>, ApiError> {
    let req = RecallReq {
        cell: cell64,
        bands: None,
        tslot: None,
    };
    let resp = recall(&req, &s).await?;
    let mut v = serde_json::to_value(resp).unwrap_or(json!({}));
    // Same b32 enrichment as /v1/ask + /v1/recall — keeps the
    // get-by-cell quick-look surface consistent with the rest of
    // the API for human/LLM legibility.
    enrich_recall_signer_b32(&mut v);
    Ok(Json(v))
}

/// REST-side wrapper for `RecallReq` that accepts a singular `band` field
/// in addition to `bands`. Agents tend to write `{"band": "modis.ndvi_mean"}`
/// — the spec defines the field as `bands: [...]` but a singular alias
/// is the most common first-call shape, so silently rejecting it (recall
/// then matches against an empty filter) is the worst possible UX. We
/// normalise to `bands: [band]` here so the auto-materializer downstream
/// sees the requested band.
#[derive(Deserialize)]
struct RecallApiReq {
    #[serde(alias = "cell64")]
    cell: String,
    #[serde(default)]
    band: Option<String>,
    #[serde(default)]
    bands: Option<Vec<String>>,
    #[serde(default)]
    tslot: Option<u64>,
}

impl From<RecallApiReq> for RecallReq {
    fn from(api: RecallApiReq) -> Self {
        // If both `band` and `bands` are supplied we merge — the singular
        // is treated as one more entry on the plural list rather than
        // silently winning.
        let bands = match (api.band, api.bands) {
            (None, None) => None,
            (Some(b), None) => Some(vec![b]),
            (None, Some(v)) => Some(v),
            (Some(b), Some(mut v)) => {
                if !v.iter().any(|x| x == &b) {
                    v.insert(0, b);
                }
                Some(v)
            }
        };
        RecallReq {
            cell: api.cell,
            bands,
            tslot: api.tslot,
        }
    }
}

async fn post_recall(
    State(s): State<AppState>,
    headers: HeaderMap,
    Json(api_req): Json<RecallApiReq>,
) -> Result<Response, ApiError> {
    metrics_inc(&RECALL_TOTAL);
    let mut req: RecallReq = api_req.into();
    // Accept place names: `recall {"cell":"Mount Everest"}` is just
    // `locate` + `recall` from the agent's POV, no reason to make
    // them do two round-trips.
    let (cell, resolved) = resolve_cell_field(&req.cell).await?;
    req.cell = cell;
    let (resp, materialize_notes) = recall_with_auto_materialize(&req, &s).await?;

    // ETag derivation: blake3 of the sorted fact_cids list. Facts are
    // content-addressed and immutable, so the same recall on the same cell
    // with the same band/tslot filter returns the same ETag bit-exactly.
    // The receipt's `served_at` differs each call, but the cite-able
    // payload (the facts) doesn't — agents repeating a recall during a
    // session can short-circuit on 304 Not Modified.
    let mut cids: Vec<String> = resp.receipt.fact_cids.iter().map(|c| c.0.clone()).collect();
    cids.sort();
    let mut hasher = blake3::Hasher::new();
    for c in &cids {
        hasher.update(c.as_bytes());
        hasher.update(b"\n");
    }
    let etag = format!("\"{}\"", &hasher.finalize().to_hex().to_string()[..16]);

    if let Some(inm) = headers.get(IF_NONE_MATCH).and_then(|v| v.to_str().ok()) {
        if inm.split(',').map(|s| s.trim()).any(|s| s == etag) {
            return Ok(Response::builder()
                .status(StatusCode::NOT_MODIFIED)
                .header(ETAG, &etag)
                .body(axum::body::Body::empty())
                .unwrap_or_else(|_| StatusCode::NOT_MODIFIED.into_response()));
        }
    }

    // Attach materialize_notes to the body when any band was attempted
    // and skipped. Cheap to skip when the array is empty (no key emitted).
    let resolved_env = resolved_envelope(vec![("cell".into(), resolved)]);
    let body = {
        let mut v = serde_json::to_value(&resp).unwrap_or(json!({}));
        // Per-fact band_metadata + value_decoded so an LLM does not have
        // to call /v1/bands separately to interpret a numeric value.
        // Walks the `facts[]` array in place; non-Primary entries are
        // left untouched.
        enrich_facts_with_metadata(&mut v);
        // Sibling `signer_pubkey_b32` per fact and
        // `responder_pubkey_b32` on the receipt — same enrichment
        // /v1/ask applies, so an LLM can quote signers without
        // touching the raw 32-byte arrays.
        enrich_recall_signer_b32(&mut v);
        if let Some(map) = v.as_object_mut() {
            if !materialize_notes.is_empty() {
                map.insert(
                    "materialize_notes".into(),
                    JsonValue::Array(materialize_notes),
                );
            }
            if let Some(env) = resolved_env {
                map.insert("resolved_from".into(), env);
            }
        }
        serde_json::to_vec(&v).unwrap_or_else(|_| b"{}".to_vec())
    };
    Ok(Response::builder()
        .status(StatusCode::OK)
        .header(CONTENT_TYPE, "application/json; charset=utf-8")
        .header(ETAG, &etag)
        // 60s — short, because new facts may land on this cell from any
        // other agent and the immutable cite-ability is per-fact, not
        // per-recall. Long enough to dedupe within an agent's reasoning
        // loop, short enough that contributions become visible quickly.
        .header(CACHE_CONTROL, "private, max-age=60")
        .body(axum::body::Body::from(body))
        .unwrap_or_else(|_| StatusCode::INTERNAL_SERVER_ERROR.into_response()))
}

// =============================================================
// Boring-API skin: lat/lng GETs over the deep recall protocol.
//
// Why: agents trained on the public API zoo (OpenWeather, Maps,
// Stripe…) reach for `GET /thing?lat=&lon=` first; cell64 + body-
// POST is a wall on the activation path. The boring layer runs
// locate→recall internally and returns a flat scalar + the protocol
// citizenship (cell64, fact_cid, responder_pubkey_b32, signed_at)
// so a one-liner curl works AND every guarantee is preserved.
// Agents that need polygons / batches / history graduate to
// /v1/recall, /v1/recall_polygon, /v1/backfill via the `next` hints.
//
// Honesty fields surfaced by every boring response:
//   resolution_m_input — sensor's native pitch (10 m for S1/S2,
//                        90 m for Cop-DEM, 250 m for SoilGrids…)
//   cell_dedupe_m      — cell64 grid grain (~10 m × ~10 m square at
//                        the equator; see /v1/grid_info)
// Two queries 12 m apart resolve to distinct cell64s — there is no
// sub-cell silent dedupe at the boring API surface.
// =============================================================

#[derive(Deserialize)]
struct LatLngQ {
    /// Optional so the query can fall back to `place` (free-text place
    /// name resolved through the standard locate path). When `place` is
    /// absent, `lat` is required — `resolve_target` enforces that.
    #[serde(default)]
    lat: Option<f64>,
    #[serde(default)]
    lon: Option<f64>,
    #[serde(default)]
    lng: Option<f64>,
    /// Free-text place name. Aliases match `/v1/locate` so an agent
    /// transferring patterns from another geocoder lands on the right
    /// field. When set, the boring handler runs `locate_inner` and uses
    /// the resulting lat/lng — same provenance string is surfaced.
    #[serde(default, alias = "q", alias = "query", alias = "name")]
    place: Option<String>,
    #[serde(default)]
    band: Option<String>,
    #[serde(default)]
    bands: Option<String>,
    #[serde(default)]
    tslot: Option<u64>,
    /// Polygon-aggregation knob for boring endpoints. When `place`
    /// resolves to an OSM feature with extent (airport, park, lake,
    /// region) and `n_cells` is unset, single-band endpoints fan out to
    /// 16 sample cells inside the bbox and aggregate (mean/median/mode);
    /// `/v1/at` defaults to 1 to keep its multi-band cost cheap.
    /// `n_cells: 1` forces point behaviour at the centroid; values in
    /// `2..=64` are honoured. Anything else returns 400 — heavy queries
    /// belong on POST /v1/recall_polygon.
    #[serde(default)]
    n_cells: Option<usize>,
}

impl LatLngQ {
    fn longitude(&self) -> Result<f64, ApiError> {
        self.lon.or(self.lng).ok_or_else(|| {
            ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: "missing `lon` (or `lng`) query parameter".into(),
                    details: None,
                },
            )
        })
    }

    /// Validate `n_cells` against the boring-endpoint contract: must be
    /// `1..=64` when supplied. The hard cap distinguishes the boring
    /// surface (snappy default-of-16, cap 64) from POST /v1/recall_polygon
    /// (raw per-cell, cap 1024). Returns 400 on out-of-range so an agent
    /// learns its own bug instead of silently getting a wrong answer.
    fn validate_n_cells(&self) -> Result<(), ApiError> {
        if let Some(n) = self.n_cells {
            if !(1..=64).contains(&n) {
                return Err(ApiError(
                    StatusCode::BAD_REQUEST,
                    ErrorBody {
                        code: ErrorCode::InvalidArgument,
                        message: format!("n_cells must be in 1..=64 (got {n}). For larger fan-outs use POST /v1/recall_polygon."),
                        details: None,
                    },
                ));
            }
        }
        Ok(())
    }

    /// Resolve to a `ResolvedTarget`. When the request supplied direct
    /// `lat`/`lng`, the polygon is `None` (the user gave us a point —
    /// no geocoder, no polygon to inherit). When `place` was given, runs
    /// `locate_inner` and surfaces `polygon_bbox` + `polygon_sample_cells`
    /// from the locate response; the sample list is downsampled to
    /// `default_n` (or `n_cells` when supplied) via `sample_cells_in_bbox`
    /// so the same uniform-stride logic the polygon endpoint uses applies
    /// here too.
    ///
    /// `default_n` is the fan-out an endpoint wants when polygon is
    /// detected and `n_cells` is unset (16 for single-band, 1 for
    /// `/v1/at`). `n_cells = 1` forces point behaviour even when a
    /// polygon is present — caller wants a single value at the centroid.
    async fn resolve_target(&self, default_n: usize) -> Result<ResolvedTarget, ApiError> {
        self.validate_n_cells()?;
        // Direct lat/lng: no geocoder, no polygon. Behaviour identical
        // to the pre-polygon code path so existing point-callers don't
        // see any envelope drift.
        if let Some(la) = self.lat {
            let lo = self.longitude()?;
            return Ok(ResolvedTarget {
                lat: la,
                lng: lo,
                via: "input_latlng".to_string(),
                polygon: None,
            });
        }
        let p = self.place.as_deref().ok_or_else(|| {
            ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: "supply (lat, lon|lng) or place".into(),
                    details: None,
                },
            )
        })?;
        let lr = LocateReq {
            lat: None,
            lng: None,
            place: Some(p.to_string()),
        };
        let resp = locate_inner(lr).await?;
        let body = &resp.0;
        let la = body
            .get("lat_input")
            .and_then(|v| v.as_f64())
            .ok_or_else(|| {
                ApiError(
                    StatusCode::NOT_FOUND,
                    ErrorBody {
                        code: ErrorCode::NoGeocoderMatch,
                        message: format!("locate succeeded for '{p}' but no lat_input"),
                        details: None,
                    },
                )
            })?;
        let lo = body
            .get("lng_input")
            .and_then(|v| v.as_f64())
            .ok_or_else(|| {
                ApiError(
                    StatusCode::NOT_FOUND,
                    ErrorBody {
                        code: ErrorCode::NoGeocoderMatch,
                        message: format!("locate succeeded for '{p}' but no lng_input"),
                        details: None,
                    },
                )
            })?;
        let via = body
            .get("via")
            .and_then(|v| v.as_str())
            .unwrap_or("locate")
            .to_string();
        let via = format!("locate:{via}");

        // n_cells == 1 forces point mode even if a polygon is available.
        // Same envelope as a direct-lat/lng call (no polygon block).
        let want_n = self.n_cells.unwrap_or(default_n);
        if want_n <= 1 {
            return Ok(ResolvedTarget {
                lat: la,
                lng: lo,
                via,
                polygon: None,
            });
        }

        // Pull the polygon out of the locate response. Same shape the
        // /v1/recall_polygon handler reads.
        let polygon = if let Some(JsonValue::Object(m)) = body.get("polygon_bbox") {
            let g = |k: &str| m.get(k).and_then(|v| v.as_f64());
            match (g("min_lat"), g("max_lat"), g("min_lng"), g("max_lng")) {
                (Some(min_lat), Some(max_lat), Some(min_lng), Some(max_lng)) => {
                    let bbox = (min_lat, max_lat, min_lng, max_lng);
                    let source = m
                        .get("source")
                        .and_then(|v| v.as_str())
                        .unwrap_or("nominatim_boundingbox")
                        .to_string();
                    // locate_inner returns up to 64 cells; downsample to
                    // `want_n` via the same uniform-stride helper so the
                    // grid is honest at the requested granularity.
                    let sample_cells = sample_cells_in_bbox(bbox, want_n);
                    let place_label = body
                        .get("place_label")
                        .and_then(|v| v.as_str())
                        .map(|s| s.to_string());
                    Some(ResolvedPolygon {
                        bbox,
                        sample_cells,
                        place_label,
                        source,
                    })
                }
                _ => None,
            }
        } else {
            None
        };
        Ok(ResolvedTarget {
            lat: la,
            lng: lo,
            via,
            polygon,
        })
    }
}

/// Resolved target for a boring-endpoint call. When `polygon` is
/// `Some`, the geocoder returned an OSM feature with extent and the
/// handler should fan out to `polygon.sample_cells` and aggregate;
/// when `None`, behave exactly like the legacy single-cell path.
#[derive(Clone)]
struct ResolvedTarget {
    lat: f64,
    lng: f64,
    via: String,
    polygon: Option<ResolvedPolygon>,
}

#[derive(Clone)]
struct ResolvedPolygon {
    /// `(min_lat, max_lat, min_lng, max_lng)` — same axis order
    /// `sample_cells_in_bbox` consumes.
    bbox: (f64, f64, f64, f64),
    sample_cells: Vec<String>,
    place_label: Option<String>,
    /// Mirrors the `polygon_bbox.source` string the geocoder emits:
    /// `wide_bbox_table`, `nominatim_boundingbox`, etc. Surfaced so
    /// agents can detect when the geocoder fell back to a coarser
    /// extent — same place-name-drift mitigation /v1/recall_polygon
    /// uses.
    source: String,
}

/// Per-band aggregation kind. Inferred from the band key the same way
/// `band_input_resolution_m` is. Drives which aggregator the polygon
/// fan-out uses (mean/median for numeric, mode for categorical, vector
/// centroid for embeddings, per-component for multidim). Distinct
/// from `BandKind` (the temporal cadence enum further down) — this one
/// is purely about how to reduce N per-cell values to a headline.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum AggKind {
    NumericScalar,
    Categorical,
    VectorEmbedding,
    Multidim,
}

fn band_agg_kind(band: &str) -> AggKind {
    // Categorical: integer class IDs. Mode + class distribution makes
    // sense; mean does not.
    if matches!(
        band,
        "esa_worldcover.lc_2021" | "landcover" | "ecoregions" | "koppen" | "admin"
    ) {
        return AggKind::Categorical;
    }
    // Vector embedding: per-cell array of floats. Centroid (mean per
    // dim) is the natural aggregate; fall back to first cell when the
    // value isn't actually an array.
    if band.starts_with("geotessera") {
        return AggKind::VectorEmbedding;
    }
    // Multidim scalar bands — small fixed-length vectors of named
    // components. Treat as per-component numeric. (Today: `dem`,
    // phenology triples; bands-v0 metadata keys this off `scalar_keys`.)
    if matches!(band, "dem" | "phenology") {
        return AggKind::Multidim;
    }
    AggKind::NumericScalar
}
/// the band has no single defensible figure (e.g. embedding bands).
fn band_input_resolution_m(band: &str) -> Option<u32> {
    match band {
        b if b.starts_with("s2.") || b.starts_with("indices.") => Some(10),
        "sentinel1_raw" => Some(10),
        b if b.starts_with("geotessera") => Some(10),
        "modis.ndvi_mean" => Some(250),
        b if b.starts_with("modis.lst_") => Some(1000),
        b if b.starts_with("modis.") => Some(500),
        "copdem30m.elevation_mean" => Some(90),
        "gmrt.topobathy_mean" => Some(100),
        "surface_water.recurrence" => Some(30),
        b if b.starts_with("hansen.") => Some(30),
        // `forest_change.*` are the canonical agent-facing names for
        // the same Hansen GFC layers — 30 m native pixel grid.
        b if b.starts_with("forest_change.") => Some(30),
        "esa_worldcover.lc_2021" => Some(10),
        b if b.starts_with("soilgrids.") => Some(250),
        b if b.starts_with("cams.") => Some(11_000),
        b if b.starts_with("era5.") => Some(11_000),
        b if b.starts_with("power.") => Some(55_000),
        b if b.starts_with("weather.") => Some(2_500),
        b if b.starts_with("marine.") => Some(11_000),
        b if b.starts_with("overture.") => Some(305),
        // WorldPop wpgppop is a 100 m global per-country product;
        // the materialiser integrates over a 1 km² window to yield
        // people · km⁻², so the *effective* fact resolution is 1 km.
        "population" => Some(1_000),
        _ => None,
    }
}

/// Cell-grid grain at the equator, in metres. Square ~10 m × ~10 m
/// pixels (21 bits lat × 22 bits lng — see `emem-codec/src/geo.rs`).
/// Single source of truth: `/v1/grid_info`.
const RESOLUTION_M_GRID: u32 = 10;

// =============================================================
// Band-metadata helpers — embed interpretation/units/value_range
// + a categorical-class decode table directly in every numeric
// response. Without this, an LLM consuming `value: 50,
// unit: "lccs_class"` has to make a separate `/v1/bands` call to
// translate it to "Built-up", and the more costly cases (mistaking
// `elevation_m: 0.0` for sea level over open ocean) never get
// caught at all.
// =============================================================

/// Class-decode tables for categorical bands. Keyed by the dotted
/// scalar key (e.g. `esa_worldcover.lc_2021`) as well as the cube
/// alias (`landcover`) so both materialized and aggregated views
/// resolve. Class IDs are signed i64 to match the JSON-decoded form
/// of the value in the response.
fn class_decode_for(band: &str) -> Option<&'static [(i64, &'static str)]> {
    // ESA WorldCover 2021 v200 LCCS class codes.
    // Source: https://esa-worldcover.org (legend appendix).
    const WORLDCOVER: &[(i64, &str)] = &[
        (10, "Tree cover"),
        (20, "Shrubland"),
        (30, "Grassland"),
        (40, "Cropland"),
        (50, "Built-up"),
        (60, "Bare / sparse vegetation"),
        (70, "Snow and ice"),
        (80, "Permanent water bodies"),
        (90, "Herbaceous wetland"),
        (95, "Mangroves"),
        (100, "Moss and lichen"),
    ];
    // JRC Global Surface Water transition class. 12-D `surface_water`
    // dimension `transition_class` carries these codes.
    const SURFACE_WATER_TRANSITION: &[(i64, &str)] = &[
        (0, "No change"),
        (1, "Permanent"),
        (2, "New permanent"),
        (3, "Lost permanent"),
        (4, "Seasonal"),
        (5, "New seasonal"),
        (6, "Lost seasonal"),
        (7, "Seasonal to permanent"),
        (8, "Permanent to seasonal"),
        (9, "Ephemeral permanent"),
        (10, "Ephemeral seasonal"),
    ];
    // Sentinel-2 Scene Classification Layer (SCL). Per Sen2Cor / S2 L2A
    // documentation; the only 4-bit categorical band materialized today.
    const S2_SCL: &[(i64, &str)] = &[
        (0, "No data"),
        (1, "Saturated or defective"),
        (2, "Cast shadows"),
        (3, "Cloud shadows"),
        (4, "Vegetation"),
        (5, "Bare soil"),
        (6, "Water"),
        (7, "Cloud (low probability)"),
        (8, "Cloud (medium probability)"),
        (9, "Cloud (high probability)"),
        (10, "Thin cirrus"),
        (11, "Snow / ice"),
    ];
    match band {
        "esa_worldcover.lc_2021" | "landcover" => Some(WORLDCOVER),
        "surface_water.transition_class" => Some(SURFACE_WATER_TRANSITION),
        "s2.scl" => Some(S2_SCL),
        _ => None,
    }
}

/// Decode a categorical class ID to a label. Returns `None` when the
/// band has no decode table or the class is not in the codebook.
fn decode_class_value(band: &str, value_json: &JsonValue) -> Option<String> {
    let table = class_decode_for(band)?;
    let class_id = value_json
        .as_i64()
        .or_else(|| value_json.as_f64().map(|f| f.round() as i64))?;
    table
        .iter()
        .find(|(id, _)| *id == class_id)
        .map(|(_, lab)| lab.to_string())
}

/// Build a `band_metadata` JSON block sourced from the cached band
/// registry. Includes description / units / value_range / interpretation
/// / pitfalls / references and, for categorical bands, a `class_decode`
/// map of class_id → label. Returns `JsonValue::Null` when the band
/// isn't in the registry AND has no class_decode table — callers can
/// use `is_null()` to decide whether to skip the field.
///
/// Lookups go through `BandRegistry::lookup` which is O(n) over ~33
/// bands, ~µs per call. Hot paths that call this in a loop should hoist
/// the `key_index` themselves; for the boring single-fact / aggregated
/// paths the per-call cost is dominated by the upstream materializer.
fn band_metadata_for_response(band_key: &str) -> JsonValue {
    let registry = &*emem_core::bands::DEFAULT;
    // Bands with dots ("esa_worldcover.lc_2021", "copdem30m.elevation_mean")
    // are materializer scalars that ride atop a cube band; they don't
    // appear directly in the registry. Map them to their cube band so
    // the editorial fields still surface. The map below is the inverse
    // of the family-alias map derived in `/v1/coverage_matrix` from
    // `bands-v0.json` `scalar_keys` — both views must stay in sync
    // when adding a new scalar to a family band.
    let cube_band = match band_key {
        // Cop-DEM scalars → `cop_dem` slot.
        b if b.starts_with("copdem30m.") => "cop_dem",
        // GMRT bathymetry rides on the legacy `dem` slot today.
        "gmrt.topobathy_mean" => "dem",
        // ESA WorldCover scalar → `landcover` slot.
        "esa_worldcover.lc_2021" => "landcover",
        // Indices.* and s2.* → their respective family slots.
        b if b.starts_with("indices.") => "indices",
        b if b.starts_with("s2.") => "sentinel2_raw",
        b if b.starts_with("geotessera") => "geotessera",
        b if b.starts_with("overture.") => "overture",
        b if b.starts_with("weather.") => "climate",
        b if b.starts_with("surface_water.") => "surface_water",
        b if b.starts_with("hansen.") => "forest_change",
        // Canonical `forest_change.*` sub-bands resolve directly to the
        // `forest_change` cube slot — kept here next to the legacy
        // `hansen.*` arm so adding either form picks up the family
        // editorial fields (description / interpretation / …).
        b if b.starts_with("forest_change.") => "forest_change",
        b if b.starts_with("modis.lst_") || b.starts_with("modis.ndvi") => "indices",
        b if b.starts_with("soilgrids.") => "soilgrids",
        // CAMS scalars now have a dedicated `air_quality` band entry
        // (carved 7 dims off the front of `_reserved_512` in
        // bands-v0.json on 2026-05-04). Per-pollutant units +
        // value_range live in dimensions[]; the dimension lookup
        // below pulls the right one by name.
        b if b.starts_with("cams.") => "air_quality",
        _ => band_key,
    };
    let band_entry = registry
        .lookup(cube_band)
        .or_else(|| registry.lookup(band_key));
    let mut map = serde_json::Map::new();
    if let Some(b) = band_entry {
        if let Some(d) = &b.description {
            map.insert("description".into(), json!(d));
        }
        if let Some(u) = &b.units {
            map.insert("units".into(), json!(u));
        }
        if let Some(vr) = &b.value_range {
            map.insert("value_range".into(), vr.clone());
        }
        if let Some(it) = &b.interpretation {
            map.insert("interpretation".into(), json!(it));
        }
        if let Some(p) = &b.pitfalls {
            map.insert("pitfalls".into(), json!(p));
        }
        if let Some(r) = &b.references {
            map.insert("references".into(), json!(r));
        }
        // Per-scalar dimension overlay: when the dotted `band_key`
        // suffix matches a `dimensions[].name`, surface ITS units +
        // value_range + description so an LLM doesn't read
        // "see scalar_keys" as a unit. Top-level fields stay as the
        // band-wide context (description / pitfalls / references) while
        // the per-dim record overrides the value-shape fields.
        if cube_band != band_key {
            if let Some(suffix) = band_key.split('.').next_back() {
                // Some scalar names embed array notation
                // (e.g. "buildings.class_freq[12]"); strip the bracket
                // tail before comparing so a `.class_freq` request
                // still resolves.
                let suffix_norm = suffix.split('[').next().unwrap_or(suffix);
                if let Some(dim) = b.dimensions.iter().find(|d| {
                    d.name == suffix || d.name.split('[').next().unwrap_or(&d.name) == suffix_norm
                }) {
                    if let Some(u) = &dim.units {
                        map.insert("units".into(), json!(u));
                    }
                    if let Some(vr) = &dim.value_range {
                        map.insert("value_range".into(), vr.clone());
                    }
                    map.insert("dimension_description".into(), json!(dim.description));
                    map.insert("dimension_index".into(), json!(dim.index));
                    if let Some(f) = &dim.formula {
                        map.insert("formula".into(), json!(f));
                    }
                }
            }
            map.insert("inherited_from_cube_band".into(), json!(cube_band));
        }
    }
    if let Some(table) = class_decode_for(band_key) {
        let decode: serde_json::Map<String, JsonValue> = table
            .iter()
            .map(|(id, lab)| (id.to_string(), json!(lab)))
            .collect();
        map.insert("class_decode".into(), JsonValue::Object(decode));
    }
    if map.is_empty() {
        JsonValue::Null
    } else {
        JsonValue::Object(map)
    }
}

/// Enrich a serialized `RecallResp.facts[]` (or any JSON object that
/// holds a `facts` array of fact-shaped objects) in place: every fact
/// gains a `band_metadata` block and, when the band is categorical,
/// a `value_decoded` label. Handles objects with a top-level `facts`
/// array as well as bare arrays of facts. Non-fact JSON is left alone.
fn enrich_facts_with_metadata(value: &mut JsonValue) {
    enrich_facts_inner(value, true);
}

/// Enrich facts in-place with `value_decoded` (always) and
/// `band_metadata` (only when `with_band_metadata` is true).
///
/// The split exists because `band_metadata` is fixed per band — the
/// same blob duplicated on every fact across N cells is pure bloat
/// in regional fan-outs (deepscan 2026-05-05: ~8 KB on a 16-fact
/// recall_polygon). recall_polygon prefers to hoist a single keyed
/// map onto the response root and call this helper with
/// `with_band_metadata=false`. Single-cell `/v1/recall` keeps the
/// per-fact form because there is at most one fact per band and
/// the duplication cost is zero.
fn enrich_facts_inner(value: &mut JsonValue, with_band_metadata: bool) {
    let facts_arr = match value {
        JsonValue::Object(map) => match map.get_mut("facts") {
            Some(JsonValue::Array(arr)) => arr,
            _ => return,
        },
        JsonValue::Array(arr) => arr,
        _ => return,
    };
    for fact in facts_arr.iter_mut() {
        let Some(obj) = fact.as_object_mut() else {
            continue;
        };
        // Wire format wraps the fact variant inside one of {Primary,Absence,…}
        // OR carries `band` directly when serialized via the protocol.
        // Handle the wrapped-variant form first, then fall through.
        let band = obj
            .get("band")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string())
            .or_else(|| {
                obj.get("Primary")
                    .and_then(|p| p.get("band"))
                    .and_then(|v| v.as_str())
                    .map(|s| s.to_string())
            })
            .or_else(|| {
                obj.get("Absence")
                    .and_then(|p| p.get("band"))
                    .and_then(|v| v.as_str())
                    .map(|s| s.to_string())
            });
        let Some(band) = band else { continue };
        // value_decoded for categorical bands (Primary path only).
        let value_for_decode = obj
            .get("value")
            .cloned()
            .or_else(|| obj.get("Primary").and_then(|p| p.get("value")).cloned());
        if let Some(v) = value_for_decode {
            if let Some(label) = decode_class_value(&band, &v) {
                obj.insert("value_decoded".into(), json!(label));
            }
        }
        if with_band_metadata {
            let meta = band_metadata_for_response(&band);
            if !meta.is_null() {
                obj.insert("band_metadata".into(), meta);
            }
        }
    }
}

/// Collect the unique set of band keys present across the `facts[]`
/// array of a recall response. Used to hoist a single
/// top-level `band_metadata` map for fan-out endpoints (recall_polygon)
/// rather than duplicating the same blob on every fact.
fn unique_band_keys_in_facts(value: &JsonValue) -> Vec<String> {
    let facts_arr = match value {
        JsonValue::Object(map) => match map.get("facts") {
            Some(JsonValue::Array(arr)) => arr,
            _ => return Vec::new(),
        },
        JsonValue::Array(arr) => arr,
        _ => return Vec::new(),
    };
    let mut seen: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
    for fact in facts_arr {
        let Some(obj) = fact.as_object() else {
            continue;
        };
        let band = obj
            .get("band")
            .and_then(|v| v.as_str())
            .or_else(|| {
                obj.get("Primary")
                    .and_then(|p| p.get("band"))
                    .and_then(|v| v.as_str())
            })
            .or_else(|| {
                obj.get("Absence")
                    .and_then(|p| p.get("band"))
                    .and_then(|v| v.as_str())
            });
        if let Some(b) = band {
            seen.insert(b.to_string());
        }
    }
    seen.into_iter().collect()
}

/// Project a Fact + receipt-context into the boring response shape.
/// Returns `(value-or-null, json blob)` so the caller can decide how
/// to compose multi-band bundles.
fn boring_view(
    fact: &emem_fact::Fact,
    fact_cid: Option<&str>,
    responder_pubkey_b32: &str,
    cell64: &str,
    served_at: &str,
) -> JsonValue {
    use emem_fact::Fact;
    match fact {
        Fact::Primary(p) => {
            let source = p.sources.first();
            let res_in = band_input_resolution_m(&p.band);
            let value_json = ciborium_to_json(&p.value);
            let value_decoded = decode_class_value(&p.band, &value_json);
            // Surface every source — not just the first. A composite
            // materializer (e.g. NDVI from a S2 stack) cites multiple
            // upstream tiles; truncating to `[0]` hides provenance.
            // Hash is hex-encoded (32 raw bytes → 64 hex chars) so it
            // survives the JSON round-trip.
            let sources_full: Vec<JsonValue> = p
                .sources
                .iter()
                .map(|s| {
                    json!({
                        "scheme": s.scheme,
                        "id": s.id,
                        "captured_at": s.captured_at,
                        "url": s.url,
                        "cid": s.cid,
                        "hash_sha256_hex": s.hash.as_ref().map(|h| {
                            let mut hex = String::with_capacity(64);
                            for b in h.iter() {
                                hex.push_str(&format!("{:02x}", b));
                            }
                            hex
                        }),
                    })
                })
                .collect();
            let mut blob = json!({
                "kind":                  "primary",
                "band":                  p.band,
                "value":                 value_json,
                "unit":                  p.unit,
                "confidence":            p.confidence,
                "source":                source.map(|s| s.scheme.as_str()),
                "source_url":            source.map(|s| s.id.as_str()),
                "sources":               sources_full,
                "captured_at":           source.and_then(|s| s.captured_at.as_deref()),
                "data_resolution_m":     res_in,
                "resolution_m_input":    res_in,
                "cell_dedupe_m":         RESOLUTION_M_GRID,
                "cell64":                cell64,
                "fact_cid":              fact_cid,
                "responder_pubkey_b32":  responder_pubkey_b32,
                "signed_at":             p.signed_at,
                "served_at":             served_at,
                "tslot":                 p.tslot,
                "derivation_fn_key":     p.derivation.fn_key.as_str(),
            });
            if let Some(label) = value_decoded {
                if let Some(map) = blob.as_object_mut() {
                    map.insert("value_decoded".into(), json!(label));
                }
            }
            let meta = band_metadata_for_response(&p.band);
            if !meta.is_null() {
                if let Some(map) = blob.as_object_mut() {
                    map.insert("band_metadata".into(), meta);
                }
            }
            blob
        }
        Fact::Absence(a) => {
            let mut blob = json!({
                "kind":                  "absence",
                "band":                  a.band,
                "value":                 JsonValue::Null,
                "reason_cid":            a.reason_cid.as_str(),
                "data_resolution_m":     band_input_resolution_m(&a.band),
                "resolution_m_input":    band_input_resolution_m(&a.band),
                "cell_dedupe_m":         RESOLUTION_M_GRID,
                "cell64":                cell64,
                "fact_cid":              fact_cid,
                "responder_pubkey_b32":  responder_pubkey_b32,
                "signed_at":             a.signed_at,
                "served_at":             served_at,
                "tslot":                 a.tslot,
                "advice": "signed Absence is a real answer ('tried and got no answer'); do not retry",
            });
            let meta = band_metadata_for_response(&a.band);
            if !meta.is_null() {
                if let Some(map) = blob.as_object_mut() {
                    map.insert("band_metadata".into(), meta);
                }
            }
            blob
        }
        _ => json!({
            "kind":                  "other",
            "band":                  null,
            "cell64":                cell64,
            "responder_pubkey_b32":  responder_pubkey_b32,
            "advice": "use POST /v1/recall for non-Primary/Absence fact kinds (Range, Range2, Vector, …)",
        }),
    }
}

/// Common worker for every boring GET. Resolves lat/lng → cell64,
/// fans out to the requested band(s), runs auto-materialize, and
/// returns a flat JSON value.
async fn boring_recall_at(
    state: &AppState,
    lat: f64,
    lng: f64,
    bands: &[String],
    tslot: Option<u64>,
) -> Result<JsonValue, ApiError> {
    if !lat.is_finite() || !lng.is_finite() {
        return Err(ApiError(
            StatusCode::BAD_REQUEST,
            ErrorBody {
                code: ErrorCode::InvalidArgument,
                message: "lat/lon must be finite numbers".into(),
                details: None,
            },
        ));
    }
    if !(-90.0..=90.0).contains(&lat) || !(-180.0..=180.0).contains(&lng) {
        return Err(ApiError(
            StatusCode::BAD_REQUEST,
            ErrorBody {
                code: ErrorCode::InvalidArgument,
                message: "lat must be in [-90,90], lon in [-180,180]".into(),
                details: None,
            },
        ));
    }
    let cell = emem_codec::cell_from_latlng(lat, lng);
    let cell_str = emem_codec::to_cell64(cell);
    let req = RecallReq {
        cell: cell_str.clone(),
        bands: if bands.is_empty() {
            None
        } else {
            Some(bands.to_vec())
        },
        tslot,
    };
    let (resp, materialize_notes) = recall_with_auto_materialize(&req, state).await?;

    let pubkey_b32 = data_encoding::BASE32_NOPAD
        .encode(&state.identity.pubkey.0)
        .to_lowercase();
    let served_at = resp.receipt.served_at.clone();
    let cid_for = |band: &str| -> Option<String> {
        for (idx, fact) in resp.facts.iter().enumerate() {
            let fact_band = match fact {
                emem_fact::Fact::Primary(p) => Some(p.band.as_str()),
                emem_fact::Fact::Absence(a) => Some(a.band.as_str()),
                _ => None,
            };
            if fact_band == Some(band) {
                return resp.receipt.fact_cids.get(idx).map(|c| c.0.clone());
            }
        }
        None
    };
    let mut by_band = serde_json::Map::new();
    for fact in &resp.facts {
        let band = match fact {
            emem_fact::Fact::Primary(p) => p.band.clone(),
            emem_fact::Fact::Absence(a) => a.band.clone(),
            _ => continue,
        };
        let cid = cid_for(&band);
        by_band.insert(
            band.clone(),
            boring_view(fact, cid.as_deref(), &pubkey_b32, &cell_str, &served_at),
        );
    }

    // If a single-band request returned exactly one fact, hoist it
    // to the top level so `value` is reachable without a band lookup.
    let single = bands.len() == 1 && resp.facts.len() == 1;
    let mut envelope = if single {
        if let Some(only) = by_band.into_iter().next() {
            only.1
        } else {
            JsonValue::Null
        }
    } else {
        // Multi-band envelope: each entry under `bands` is a full Fact
        // view; hoist the protocol-citizen fields (cell64, the responder
        // pubkey, both resolution numbers) to the top so an agent that
        // only reads the first level still gets the citation surface.
        json!({
            "bands":                by_band,
            "cell64":               cell_str.clone(),
            "responder_pubkey_b32": pubkey_b32.clone(),
            "cell_dedupe_m":        RESOLUTION_M_GRID,
            "served_at":            served_at.clone(),
        })
    };

    if let Some(map) = envelope.as_object_mut() {
        map.insert("lat".into(), json!(lat));
        map.insert("lon".into(), json!(lng));
        if !materialize_notes.is_empty() {
            map.insert(
                "materialize_notes".into(),
                JsonValue::Array(materialize_notes),
            );
        }
        map.insert(
            "next".into(),
            json!({
                "deep_recall":      format!("POST /v1/recall {{cell:'{cell_str}', bands:[…]}}"),
                "polygon_aggregate": "POST /v1/recall_polygon {place:'<text>', bands:[…], max_cells:9}",
                "history":          format!("POST /v1/backfill {{cell:'{cell_str}', band:'<band>', from_unix:…, to_unix:…}}"),
                "fact_dereference": "GET /v1/facts/{fact_cid}",
                "verify_offline":   "POST /v1/verify_receipt {receipt}",
            }),
        );
    }
    Ok(envelope)
}

/// Polygon-aware boring recall. When `target.polygon` is `None`,
/// delegates to `boring_recall_at` for byte-identical legacy
/// behaviour. When polygon is detected, fans out to
/// `polygon.sample_cells` in parallel (tokio JoinSet — same pattern
/// /v1/temporal_route uses) and aggregates per band: mean/median for
/// numeric scalars, mode + class distribution for categorical bands,
/// vector centroid for embeddings, per-component for multidim.
///
/// The single-band case still hoists `value` to the top level so
/// existing clients reading `body.value` get the headline aggregate
/// (mean for numeric, mode for categorical) without a band lookup —
/// `polygon` and `stats` are added alongside it.
/// FeatureCollection containing one Polygon for the resolved place's
/// bbox. Includes area + place label as Feature properties so a chat
/// client can render the outline with a label without a second call.
fn polygon_outline_geojson(
    bbox: &(f64, f64, f64, f64),
    place_label: Option<&str>,
    area_km2: f64,
    n_sample_cells: usize,
) -> JsonValue {
    let (min_lat, max_lat, min_lng, max_lng) = *bbox;
    // GeoJSON winds CCW exterior; coords are [lng, lat].
    json!({
        "type": "FeatureCollection",
        "features": [{
            "type": "Feature",
            "geometry": {
                "type": "Polygon",
                "coordinates": [[
                    [min_lng, min_lat],
                    [max_lng, min_lat],
                    [max_lng, max_lat],
                    [min_lng, max_lat],
                    [min_lng, min_lat],
                ]],
            },
            "properties": {
                "kind":           "place_bbox",
                "place_label":    place_label,
                "area_km2":       area_km2,
                "n_sample_cells": n_sample_cells,
            },
        }],
    })
}

/// FeatureCollection of per-cell sample Polygons, each carrying the
/// recalled value for `band` as a Feature property. Renders directly
/// in geojson.io / Mapbox / Leaflet without further processing.
/// Cell bbox is the cell64 quantum (~10 m at the equator) — easily
/// fits an airport-scale or larger feature with ≤64 sample cells.
fn cells_geojson_with_values(value_per_cell: &[JsonValue], band: &str) -> JsonValue {
    let mut features: Vec<JsonValue> = Vec::with_capacity(value_per_cell.len());
    for entry in value_per_cell {
        let cell = entry.get("cell").and_then(|v| v.as_str()).unwrap_or("");
        if cell.is_empty() {
            continue;
        }
        let bbox = match emem_codec::latlng_from_cell64(cell) {
            Ok(ll) => ll.bbox_deg,
            Err(_) => continue,
        };
        let value = entry.get("value").cloned().unwrap_or(JsonValue::Null);
        let kind = entry
            .get("kind")
            .and_then(|v| v.as_str())
            .unwrap_or("primary");
        features.push(json!({
            "type": "Feature",
            "geometry": {
                "type": "Polygon",
                "coordinates": [[
                    [bbox.min_lng, bbox.min_lat],
                    [bbox.max_lng, bbox.min_lat],
                    [bbox.max_lng, bbox.max_lat],
                    [bbox.min_lng, bbox.max_lat],
                    [bbox.min_lng, bbox.min_lat],
                ]],
            },
            "properties": {
                "cell":  cell,
                "band":  band,
                "value": value,
                "kind":  kind,
            },
        }));
    }
    json!({"type": "FeatureCollection", "features": features})
}

/// Query-string body for `GET /v1/places/scene_overlay.svg`.
#[derive(Debug, Clone, serde::Deserialize)]
struct PlacesOverlayQ {
    place: String,
    band: String,
    #[serde(default)]
    n_cells: Option<usize>,
    #[serde(default)]
    width: Option<u32>,
    #[serde(default)]
    height: Option<u32>,
    #[serde(default)]
    tslot: Option<u64>,
}

/// Render an SVG value-painted overlay of the resolved place's polygon.
/// One band, sample-cell density driven by `n_cells` (default 16,
/// max 64). Numeric bands → viridis-like colormap stretched across
/// the actual min/max of the recalled values; categorical bands →
/// fixed palette keyed off the integer class id; embedding bands →
/// outline only with a "no value to colour" note.
async fn get_places_scene_overlay_svg(
    State(s): State<AppState>,
    Query(q): Query<PlacesOverlayQ>,
) -> Result<axum::response::Response, ApiError> {
    let n_cells = q.n_cells.map(|n| n.clamp(1, 64)).unwrap_or(16);
    let lq = LatLngQ {
        lat: None,
        lng: None,
        lon: None,
        place: Some(q.place.clone()),
        band: Some(q.band.clone()),
        bands: None,
        tslot: q.tslot,
        n_cells: Some(n_cells),
    };
    let target = lq.resolve_target(n_cells).await?;
    let polygon = match target.polygon.as_ref() {
        Some(p) => p.clone(),
        None => {
            return Err(ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: format!(
                        "scene_overlay: place '{}' resolved to a point (no polygon_bbox); use /v1/cells/<cell>/scene.png for point queries",
                        q.place
                    ),
                    details: None,
                },
            ));
        }
    };
    let cells: Vec<String> = polygon.sample_cells.iter().take(n_cells).cloned().collect();
    if cells.is_empty() {
        return Err(ApiError(
            StatusCode::BAD_REQUEST,
            ErrorBody {
                code: ErrorCode::InvalidArgument,
                message: "scene_overlay: bbox produced no sample cells".into(),
                details: None,
            },
        ));
    }

    // Fan out per-cell recalls in parallel — same pattern as
    // boring_recall_aggregated.
    let bands_for_recall = Some(vec![q.band.clone()]);
    let mut set: tokio::task::JoinSet<(String, Option<JsonValue>)> = tokio::task::JoinSet::new();
    for cell in &cells {
        let req = RecallReq {
            cell: cell.clone(),
            bands: bands_for_recall.clone(),
            tslot: q.tslot,
        };
        let cell = cell.clone();
        let st = s.clone();
        set.spawn(async move {
            let v = recall_with_auto_materialize(&req, &st)
                .await
                .ok()
                .and_then(|(resp, _)| {
                    resp.facts.into_iter().find_map(|f| match f {
                        emem_fact::Fact::Primary(p) => Some(ciborium_to_json(&p.value)),
                        _ => None,
                    })
                });
            (cell, v)
        });
    }
    let mut per_cell: Vec<(String, Option<JsonValue>)> = Vec::with_capacity(cells.len());
    while let Some(j) = set.join_next().await {
        if let Ok(pair) = j {
            per_cell.push(pair);
        }
    }

    // Collect numeric values for stretch. Multidim values reduce to
    // their first scalar; categorical and missing skip into n_missing.
    let nums: Vec<f64> = per_cell
        .iter()
        .filter_map(|(_, v)| v.as_ref().and_then(scalar_for_overlay))
        .filter(|x| x.is_finite())
        .collect();
    let (vmin, vmax) = if nums.is_empty() {
        (0.0, 1.0)
    } else {
        let mut s = nums.clone();
        s.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
        (*s.first().unwrap(), *s.last().unwrap())
    };

    // SVG canvas. Default 512x512; preserve bbox aspect ratio.
    let (bbox_w_deg, bbox_h_deg) = (
        polygon.bbox.3 - polygon.bbox.2,
        polygon.bbox.1 - polygon.bbox.0,
    );
    let aspect = if bbox_h_deg > 0.0 {
        bbox_w_deg / bbox_h_deg
    } else {
        1.0
    };
    let w = q.width.unwrap_or(512).clamp(64, 2048);
    let h = q
        .height
        .unwrap_or(((w as f64) / aspect.max(0.1)).round() as u32)
        .clamp(64, 2048);

    let project = |lat: f64, lng: f64| -> (f64, f64) {
        let x = ((lng - polygon.bbox.2) / bbox_w_deg.max(1e-9)) * (w as f64);
        let y = (1.0 - (lat - polygon.bbox.0) / bbox_h_deg.max(1e-9)) * (h as f64);
        (x, y)
    };

    let mut svg = String::with_capacity(8192);
    svg.push_str(&format!(
        r##"<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 {w} {h}" width="{w}" height="{h}">
  <title>{} — {}</title>
  <desc>emem.dev value-painted polygon overlay; band={}, n_cells={}, vmin={:.4}, vmax={:.4}</desc>
  <rect width="{w}" height="{h}" fill="#0b0d12"/>
"##,
        polygon
            .place_label
            .as_deref()
            .unwrap_or(&q.place)
            .replace('<', "&lt;")
            .replace('>', "&gt;")
            .replace('&', "&amp;"),
        q.band,
        q.band,
        cells.len(),
        vmin,
        vmax,
    ));

    // Per-cell rectangles, viridis-mapped fill.
    for (cell, val) in &per_cell {
        let cb = match emem_codec::latlng_from_cell64(cell) {
            Ok(ll) => ll.bbox_deg,
            Err(_) => continue,
        };
        let (x0, y1) = project(cb.max_lat, cb.min_lng);
        let (x1, y0) = project(cb.min_lat, cb.max_lng);
        let cw = (x1 - x0).abs().max(1.0);
        let ch = (y1 - y0).abs().max(1.0);
        let scalar = val.as_ref().and_then(scalar_for_overlay);
        let fill = match scalar {
            Some(v) if v.is_finite() && vmax > vmin => {
                let t = ((v - vmin) / (vmax - vmin)).clamp(0.0, 1.0);
                viridis_hex(t)
            }
            Some(_) => "#444".to_string(),
            None => "#222".to_string(),
        };
        let value_label = match val {
            Some(JsonValue::Number(n)) => n.to_string(),
            Some(JsonValue::Array(a)) => format!("[{} dims]", a.len()),
            Some(JsonValue::Null) | None => "absence".to_string(),
            Some(other) => other.to_string(),
        };
        // Title carries the cell64 + recalled value so a hover tooltip
        // in any standards-compliant SVG viewer (browsers, geojson.io,
        // Mapbox vector layers) reveals the per-cell datum without
        // needing a second call. Use a literal " | " separator — SVG
        // <title> renders text-only with no newline expansion.
        svg.push_str(&format!(
            r##"  <rect x="{:.2}" y="{:.2}" width="{:.2}" height="{:.2}" fill="{}" stroke="#0b0d12" stroke-width="0.5"><title>{} | value: {}</title></rect>
"##,
            x0, y0, cw, ch, fill, cell, value_label,
        ));
    }

    // Outer bbox outline.
    svg.push_str(&format!(
        r##"  <rect x="0" y="0" width="{w}" height="{h}" fill="none" stroke="#7af" stroke-width="2"/>
"##
    ));

    // Caption strip.
    let caption = polygon
        .place_label
        .as_deref()
        .unwrap_or(&q.place)
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('&', "&amp;");
    let strip_h = 36u32;
    svg.push_str(&format!(
        r##"  <rect x="0" y="{}" width="{w}" height="{strip_h}" fill="#0b0d12" opacity="0.85"/>
  <text x="8" y="{}" fill="#eaecef" font-family="Inter, ui-sans-serif, system-ui" font-size="12">{}  ·  {}  ·  n={}  ·  [{:.4}, {:.4}]</text>
"##,
        h.saturating_sub(strip_h),
        h.saturating_sub(12),
        caption,
        q.band,
        nums.len(),
        vmin,
        vmax,
    ));

    svg.push_str("</svg>\n");

    let mut resp = axum::response::Response::new(axum::body::Body::from(svg));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("image/svg+xml; charset=utf-8"),
    );
    resp.headers_mut().insert(
        axum::http::header::CACHE_CONTROL,
        axum::http::HeaderValue::from_static("public, max-age=60"),
    );
    Ok(resp)
}

/// Reduce a value JSON to a single scalar for the overlay colormap.
/// Numbers pass through; arrays use their first finite numeric entry
/// (multidim bands like `dem` triple); everything else returns None.
fn scalar_for_overlay(v: &JsonValue) -> Option<f64> {
    match v {
        JsonValue::Number(n) => n.as_f64(),
        JsonValue::Array(a) => a.iter().find_map(|x| x.as_f64()),
        _ => None,
    }
}

/// Fast, dependency-free viridis approximation. Input t ∈ [0,1].
/// Fitted from the canonical viridis stops (8 control points, linear
/// interpolation between the nearest two).
fn viridis_hex(t: f64) -> String {
    const STOPS: [(f64, [u8; 3]); 8] = [
        (0.0, [68, 1, 84]),
        (0.143, [72, 35, 116]),
        (0.286, [64, 67, 135]),
        (0.429, [52, 94, 141]),
        (0.571, [41, 120, 142]),
        (0.714, [32, 144, 140]),
        (0.857, [34, 167, 132]),
        (1.0, [253, 231, 36]),
    ];
    let t = t.clamp(0.0, 1.0);
    let (mut lo, mut hi) = (&STOPS[0], &STOPS[STOPS.len() - 1]);
    for w in STOPS.windows(2) {
        if t >= w[0].0 && t <= w[1].0 {
            lo = &w[0];
            hi = &w[1];
            break;
        }
    }
    let span = (hi.0 - lo.0).max(1e-9);
    let f = (t - lo.0) / span;
    let mix = |a: u8, b: u8| -> u8 {
        ((a as f64) * (1.0 - f) + (b as f64) * f)
            .round()
            .clamp(0.0, 255.0) as u8
    };
    let r = mix(lo.1[0], hi.1[0]);
    let g = mix(lo.1[1], hi.1[1]);
    let b = mix(lo.1[2], hi.1[2]);
    format!("#{:02x}{:02x}{:02x}", r, g, b)
}

async fn boring_recall_aggregated(
    state: &AppState,
    target: ResolvedTarget,
    bands: &[String],
    tslot: Option<u64>,
) -> Result<JsonValue, ApiError> {
    // Point query: zero behaviour change vs the legacy code path.
    let polygon = match target.polygon.as_ref() {
        None => {
            return boring_recall_at(state, target.lat, target.lng, bands, tslot).await;
        }
        Some(p) => p.clone(),
    };

    // Sanity-bound the cell list. `resolve_target` already capped, but
    // double-check to keep the upstream-fetch budget defensible.
    let cells: Vec<String> = polygon.sample_cells.iter().take(64).cloned().collect();
    if cells.is_empty() {
        // No cells — fall back to the centroid so we always serve
        // something (matches /v1/recall_polygon's degenerate-bbox path).
        return boring_recall_at(state, target.lat, target.lng, bands, tslot).await;
    }

    // Fan out per-cell recalls concurrently. Without this a 16-cell
    // cold polygon = 16 sequential Open-Meteo / met.no fetches → 8-15s
    // per request. Mirrors commit 29f02e6 (parallel temporal recipes).
    type CellRecall = (String, Result<(RecallResp, Vec<JsonValue>), ApiError>);
    let mut set: tokio::task::JoinSet<CellRecall> = tokio::task::JoinSet::new();
    let bands_for_recall: Option<Vec<String>> = if bands.is_empty() {
        None
    } else {
        Some(bands.to_vec())
    };
    for cell in &cells {
        let req = RecallReq {
            cell: cell.clone(),
            bands: bands_for_recall.clone(),
            tslot,
        };
        let cell = cell.clone();
        let s = state.clone();
        set.spawn(async move {
            let r = recall_with_auto_materialize(&req, &s).await;
            (cell, r)
        });
    }
    let mut per_cell: Vec<(String, RecallResp)> = Vec::with_capacity(cells.len());
    let mut materialize_notes_all: Vec<JsonValue> = Vec::new();
    let mut errors: Vec<JsonValue> = Vec::new();
    while let Some(j) = set.join_next().await {
        if let Ok((cell, r)) = j {
            match r {
                Ok((resp, notes)) => {
                    materialize_notes_all.extend(notes);
                    per_cell.push((cell, resp));
                }
                Err(e) => {
                    errors.push(json!({
                        "cell": cell,
                        "code": e.1.code,
                        "message": e.1.message,
                        "status": e.0.as_u16(),
                    }));
                }
            }
        }
    }

    // Group facts by band across all cells. Track per-cell fact_cid +
    // signed_at + responder so the aggregated envelope can carry the
    // citation surface ({fact_cids: [...], captured_at_range: [...]}).
    use std::collections::BTreeMap;
    #[derive(Clone)]
    #[allow(dead_code)]
    struct PerCellFact {
        cell: String,
        fact: emem_fact::Fact,
        fact_cid: Option<String>,
        signed_at: String,
    }
    let mut by_band: BTreeMap<String, Vec<PerCellFact>> = BTreeMap::new();
    let mut latest_served_at = String::new();
    for (cell, resp) in &per_cell {
        if resp.receipt.served_at > latest_served_at {
            latest_served_at = resp.receipt.served_at.clone();
        }
        for (idx, fact) in resp.facts.iter().enumerate() {
            let (band, signed_at) = match fact {
                emem_fact::Fact::Primary(p) => (p.band.clone(), p.signed_at.clone()),
                emem_fact::Fact::Absence(a) => (a.band.clone(), a.signed_at.clone()),
                _ => continue,
            };
            let fact_cid = resp.receipt.fact_cids.get(idx).map(|c| c.0.clone());
            by_band.entry(band).or_default().push(PerCellFact {
                cell: cell.clone(),
                fact: fact.clone(),
                fact_cid,
                signed_at,
            });
        }
    }

    let pubkey_b32 = data_encoding::BASE32_NOPAD
        .encode(&state.identity.pubkey.0)
        .to_lowercase();

    // Bands the caller asked for. Use this as the iteration set so
    // requested-but-empty bands surface with `n_missing == n_cells`
    // instead of vanishing silently.
    let band_iter: Vec<String> = if bands.is_empty() {
        by_band.keys().cloned().collect()
    } else {
        bands.to_vec()
    };

    let mut bands_out = serde_json::Map::new();
    // Roll-up of missingness across bands so the response root can carry
    // a `partial: true` honesty flag — agents reading aggregate stats
    // mistake an incomplete fan-out for full coverage otherwise.
    let mut total_missing: usize = 0;
    let mut total_attempts: usize = 0;
    for band in &band_iter {
        let entries = by_band.get(band).cloned().unwrap_or_default();
        let kind = band_agg_kind(band);
        let n_total = cells.len();
        let n_present = entries.len();
        let n_missing = n_total.saturating_sub(n_present);
        // Split Primary vs Absence — only Primary feeds numeric stats.
        let mut primary_values: Vec<JsonValue> = Vec::with_capacity(entries.len());
        let mut fact_cids: Vec<String> = Vec::with_capacity(entries.len());
        let mut signed_ats: Vec<String> = Vec::with_capacity(entries.len());
        let mut absence_count = 0usize;
        let mut sample_unit: Option<String> = None;
        let mut sample_source: Option<String> = None;
        // value_per_cell carries a tuple (cell64, lat, lng, value-or-null,
        // kind: "primary"|"absence") per sample cell so an agent can plot
        // its own histogram, identify outliers, render its own choropleth,
        // or persist for downstream analysis without re-fetching.
        let mut value_per_cell: Vec<JsonValue> = Vec::with_capacity(entries.len());
        for e in &entries {
            let (lat_c, lng_c) = match emem_codec::latlng_from_cell64(&e.cell) {
                Ok(ll) => (ll.lat_deg, ll.lng_deg),
                Err(_) => (f64::NAN, f64::NAN),
            };
            let (val_json, kind_str): (JsonValue, &str) = match &e.fact {
                emem_fact::Fact::Primary(p) => (ciborium_to_json(&p.value), "primary"),
                emem_fact::Fact::Absence(_) => (JsonValue::Null, "absence"),
                _ => (JsonValue::Null, "other"),
            };
            value_per_cell.push(json!({
                "cell":  e.cell,
                "lat":   lat_c,
                "lng":   lng_c,
                "value": val_json,
                "kind":  kind_str,
                "fact_cid": e.fact_cid,
            }));
            match &e.fact {
                emem_fact::Fact::Primary(p) => {
                    primary_values.push(ciborium_to_json(&p.value));
                    if sample_unit.is_none() {
                        sample_unit = p.unit.clone();
                    }
                    if sample_source.is_none() {
                        sample_source = p.sources.first().map(|s| s.scheme.clone());
                    }
                }
                emem_fact::Fact::Absence(_) => absence_count += 1,
                _ => {}
            }
            if let Some(c) = &e.fact_cid {
                fact_cids.push(c.clone());
            }
            signed_ats.push(e.signed_at.clone());
        }
        let n_missing_eff = n_missing + absence_count;
        total_missing += n_missing_eff;
        total_attempts += n_total;

        let (aggregator, headline, stats, kind_str, extra) =
            aggregate_band(kind, &primary_values, n_present, n_missing_eff);

        let captured_at_range = if signed_ats.is_empty() {
            JsonValue::Null
        } else {
            let mut s = signed_ats.clone();
            s.sort();
            json!([s.first(), s.last()])
        };

        // Decorate value_per_cell with value_decoded for categorical bands
        // so the LLM doesn't have to consult class_decode at the band level
        // for every cell.
        if class_decode_for(band).is_some() {
            for entry in value_per_cell.iter_mut() {
                if let Some(map) = entry.as_object_mut() {
                    if let Some(v) = map.get("value").cloned() {
                        if let Some(label) = decode_class_value(band, &v) {
                            map.insert("value_decoded".into(), json!(label));
                        }
                    }
                }
            }
        }
        // Decode the headline value when categorical (mode → label).
        let headline_decoded = decode_class_value(band, &headline);
        let mut block = json!({
            "aggregator":            aggregator,
            "value":                 headline,
            "stats":                 stats,
            "kind":                  kind_str,
            "fact_cids":             fact_cids,
            "data_resolution_m":     band_input_resolution_m(band),
            "cell_dedupe_m":         RESOLUTION_M_GRID,
            "n":                     n_present,
            "n_missing":             n_missing_eff,
            "unit":                  sample_unit,
            "source":                sample_source,
            "captured_at_range":     captured_at_range,
            "responder_pubkey_b32":  pubkey_b32,
            "value_per_cell":        JsonValue::Array(value_per_cell.clone()),
            "geojson":               cells_geojson_with_values(&value_per_cell, band),
        });
        if let Some(map) = block.as_object_mut() {
            for (k, v) in extra {
                // For categorical bands, transform `class_distribution`
                // from {"50":12} to {"50":{"label":"Built-up","count":12}}
                // so the LLM doesn't have to cross-reference class IDs
                // with the band metadata to render a histogram.
                if k == "class_distribution" && class_decode_for(band).is_some() {
                    if let Some(obj) = v.as_object() {
                        let decoded: serde_json::Map<String, JsonValue> = obj
                            .iter()
                            .map(|(class_id_str, count)| {
                                let label = class_id_str
                                    .parse::<i64>()
                                    .ok()
                                    .and_then(|id| decode_class_value(band, &json!(id)))
                                    .unwrap_or_else(|| "unknown".to_string());
                                (
                                    class_id_str.clone(),
                                    json!({"label": label, "count": count}),
                                )
                            })
                            .collect();
                        map.insert(k, JsonValue::Object(decoded));
                        continue;
                    }
                }
                map.insert(k, v);
            }
            if let Some(label) = headline_decoded {
                map.insert("value_decoded".into(), json!(label));
            }
            let meta = band_metadata_for_response(band);
            if !meta.is_null() {
                map.insert("band_metadata".into(), meta);
            }
        }
        bands_out.insert(band.clone(), block);
    }

    // Area in km², same midlat formula /v1/recall_polygon uses.
    let area_km2 = {
        let mid_lat = (polygon.bbox.0 + polygon.bbox.1) / 2.0;
        let lat_km = (polygon.bbox.1 - polygon.bbox.0) * 111.0;
        let lng_km = (polygon.bbox.3 - polygon.bbox.2) * 111.0 * mid_lat.to_radians().cos().abs();
        (lat_km * lng_km).max(0.0)
    };
    // Per-cell scene/geojson URL pointers — agents can render their own
    // grid in a chat / report without re-querying. Overlay URL is a
    // server-side value-painted SVG of the polygon for the first band
    // (single-band hot path); multi-band callers can swap `?band=` to
    // get per-band overlays.
    let scene_thumbs: Vec<JsonValue> = cells
        .iter()
        .map(|c| {
            let (lat_c, lng_c) = match emem_codec::latlng_from_cell64(c) {
                Ok(ll) => (ll.lat_deg, ll.lng_deg),
                Err(_) => (f64::NAN, f64::NAN),
            };
            json!({
                "cell":         c,
                "lat":          lat_c,
                "lng":          lng_c,
                "scene_png":    format!("/v1/cells/{}/scene.png", c),
                "scene_rgb":    format!("/v1/cells/{}/scene.rgb", c),
                "geojson":      format!("/v1/cells/{}/geojson",   c),
                "info":         format!("/v1/cells/{}/info",      c),
            })
        })
        .collect();
    let overlay_band = bands.first().cloned().unwrap_or_default();
    let overlay_url = if !overlay_band.is_empty() {
        let label_for_url = polygon
            .place_label
            .as_deref()
            .map(|s| s.split(',').next().unwrap_or(s).trim().to_string())
            .unwrap_or_default();
        if label_for_url.is_empty() {
            json!(null)
        } else {
            // Percent-encode just spaces — full encoding via urlencoding
            // crate would pull in another dep; simple replace covers the
            // overwhelming majority of place labels.
            let encoded = label_for_url.replace(' ', "%20");
            json!(format!(
                "/v1/places/scene_overlay.svg?place={encoded}&band={overlay_band}&n_cells={}",
                cells.len()
            ))
        }
    } else {
        json!(null)
    };
    let polygon_block = json!({
        "bbox": {
            "min_lat": polygon.bbox.0, "max_lat": polygon.bbox.1,
            "min_lng": polygon.bbox.2, "max_lng": polygon.bbox.3,
        },
        "area_km2":         area_km2,
        "sample_cells":     cells.clone(),
        "n_sample_cells":   cells.len(),
        "source":           polygon.source,
        "geojson":          polygon_outline_geojson(&polygon.bbox, polygon.place_label.as_deref(), area_km2, cells.len()),
        "scene_thumbs":     JsonValue::Array(scene_thumbs),
        "scene_overlay_url": overlay_url,
    });

    let single = bands.len() == 1;
    let mut envelope = if single {
        // Backward-compat: hoist the single band's headline so existing
        // clients reading `body.value` keep working. Polygon block +
        // stats are layered alongside.
        let band = &bands[0];
        let band_block = bands_out
            .get(band)
            .cloned()
            .unwrap_or(JsonValue::Object(Default::default()));
        let mut env = band_block;
        if let Some(map) = env.as_object_mut() {
            map.insert("band".into(), json!(band));
        }
        env
    } else {
        json!({
            "bands":                JsonValue::Object(bands_out),
            "responder_pubkey_b32": pubkey_b32.clone(),
            "cell_dedupe_m":        RESOLUTION_M_GRID,
        })
    };

    if let Some(map) = envelope.as_object_mut() {
        map.insert("lat".into(), json!(target.lat));
        map.insert("lon".into(), json!(target.lng));
        map.insert("via".into(), json!(target.via));
        map.insert("polygon".into(), polygon_block);
        if let Some(label) = polygon.place_label {
            map.insert("place_label".into(), json!(label));
        }
        map.insert("n_cells_queried".into(), json!(cells.len()));
        map.insert("n_cells_returned".into(), json!(per_cell.len()));
        map.insert("served_at".into(), json!(latest_served_at));
        if !materialize_notes_all.is_empty() {
            map.insert(
                "materialize_notes".into(),
                JsonValue::Array(materialize_notes_all),
            );
        }
        if !errors.is_empty() {
            map.insert("cell_errors".into(), JsonValue::Array(errors));
        }
        // Honesty: an aggregated response that summarised over a partial
        // fan-out should not look identical to one with full coverage.
        // `partial: true` flips when ANY band has an unfilled cell across
        // the polygon sample (cell error, materializer skip, or signed
        // Absence). `coverage_fraction` quantifies how close to complete.
        let partial = total_missing > 0;
        let coverage_fraction = if total_attempts > 0 {
            (total_attempts - total_missing) as f64 / total_attempts as f64
        } else {
            0.0
        };
        map.insert("partial".into(), json!(partial));
        map.insert("coverage_fraction".into(), json!(coverage_fraction));
        map.insert("is_exhaustive".into(), json!(false));
        let bbox = polygon.bbox;
        map.insert(
            "next".into(),
            json!({
                "raw_per_cell":     format!("POST /v1/recall_polygon {{polygon_bbox:{{min_lat:{},max_lat:{},min_lng:{},max_lng:{}}}, bands:[…]}}", bbox.0, bbox.1, bbox.2, bbox.3),
                "deep_recall":      "POST /v1/recall {cell:'<cell64>', bands:[…]}",
                "fact_dereference": "GET /v1/facts/{fact_cid}",
                "verify_offline":   "POST /v1/verify_receipt {receipt}",
            }),
        );
        map.insert(
            "agent_hint".into(),
            json!("Polygon aggregation: when a place name resolves to a feature with extent (airport, park, lake, region), the boring endpoint fans out to `polygon.sample_cells` and returns mean/median/min/max/std per band (mode + class distribution for categorical bands like esa_worldcover.lc_2021). Pass `n_cells:1` to force a single-cell read at the centroid; use POST /v1/recall_polygon for raw per-cell facts."),
        );
    }
    Ok(envelope)
}

/// Numeric / categorical / vector / multidim aggregator. Returns
/// `(aggregator_name, headline_value, stats_block, kind_string, extra_kv)`.
/// Extra fields (e.g. `class_distribution`) are merged into the band
/// block; keeps the caller flat.
fn aggregate_band(
    kind: AggKind,
    values: &[JsonValue],
    n_present: usize,
    n_missing_eff: usize,
) -> (
    &'static str,
    JsonValue,
    JsonValue,
    &'static str,
    Vec<(String, JsonValue)>,
) {
    let mut extra: Vec<(String, JsonValue)> = Vec::new();
    match kind {
        AggKind::NumericScalar => {
            let mut nums: Vec<f64> = values.iter().filter_map(|v| v.as_f64()).collect();
            nums.retain(|x| x.is_finite());
            if nums.is_empty() {
                return (
                    "mean",
                    JsonValue::Null,
                    json!({
                        "mean":  null, "median": null, "min": null, "max": null,
                        "std":   null, "n": n_present, "n_missing": n_missing_eff,
                    }),
                    "numeric_scalar",
                    extra,
                );
            }
            let n = nums.len() as f64;
            let mean = nums.iter().sum::<f64>() / n;
            let var = nums.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / n;
            let std = var.sqrt();
            let mut sorted = nums.clone();
            sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
            let median = if sorted.len() % 2 == 1 {
                sorted[sorted.len() / 2]
            } else {
                (sorted[sorted.len() / 2 - 1] + sorted[sorted.len() / 2]) / 2.0
            };
            let min = *sorted.first().unwrap();
            let max = *sorted.last().unwrap();
            (
                "mean",
                json!(mean),
                json!({
                    "mean":  mean, "median": median, "min": min, "max": max,
                    "std":   std, "n": nums.len(), "n_missing": n_missing_eff,
                }),
                "numeric_scalar",
                extra,
            )
        }
        AggKind::Categorical => {
            use std::collections::BTreeMap;
            let mut hist: BTreeMap<i64, usize> = BTreeMap::new();
            for v in values {
                if let Some(i) = v.as_i64() {
                    *hist.entry(i).or_insert(0) += 1;
                } else if let Some(f) = v.as_f64() {
                    *hist.entry(f as i64).or_insert(0) += 1;
                }
            }
            let mode = hist.iter().max_by_key(|(_, c)| **c).map(|(k, _)| *k);
            let dist: serde_json::Map<String, JsonValue> = hist
                .iter()
                .map(|(k, v)| (k.to_string(), json!(v)))
                .collect();
            extra.push(("class_distribution".into(), JsonValue::Object(dist)));
            let total: usize = hist.values().sum();
            (
                "mode",
                mode.map(|m| json!(m)).unwrap_or(JsonValue::Null),
                json!({
                    "mode":      mode,
                    "n_classes": hist.len(),
                    "n":         total,
                    "n_missing": n_missing_eff,
                }),
                "categorical",
                extra,
            )
        }
        AggKind::VectorEmbedding => {
            // Coerce each value to Vec<f64>; skip non-arrays.
            let mut vecs: Vec<Vec<f64>> = Vec::new();
            for v in values {
                if let Some(arr) = v.as_array() {
                    let row: Vec<f64> = arr.iter().filter_map(|x| x.as_f64()).collect();
                    if !row.is_empty() {
                        vecs.push(row);
                    }
                }
            }
            if vecs.is_empty() {
                // First value (likely fp16/bytes); embedding aggregation
                // not applicable — surface a note rather than guessing.
                return (
                    "first",
                    values.first().cloned().unwrap_or(JsonValue::Null),
                    json!({
                        "n":          n_present,
                        "n_missing":  n_missing_eff,
                        "note":       "embedding aggregation not applicable for this band (per-cell value isn't a JSON array of floats)",
                    }),
                    "vector_embedding",
                    extra,
                );
            }
            let dim = vecs.iter().map(|v| v.len()).min().unwrap_or(0);
            let n = vecs.len() as f64;
            let mut centroid = vec![0.0f64; dim];
            for v in &vecs {
                for (i, x) in v.iter().take(dim).enumerate() {
                    centroid[i] += x;
                }
            }
            for x in &mut centroid {
                *x /= n;
            }
            (
                "vector_centroid",
                json!(centroid),
                json!({
                    "dim":        dim,
                    "n":          vecs.len(),
                    "n_missing":  n_missing_eff,
                }),
                "vector_embedding",
                extra,
            )
        }
        AggKind::Multidim => {
            // Per-component mean/median/min/max for an array-of-floats band.
            let mut rows: Vec<Vec<f64>> = Vec::new();
            for v in values {
                if let Some(arr) = v.as_array() {
                    let row: Vec<f64> = arr.iter().filter_map(|x| x.as_f64()).collect();
                    if !row.is_empty() {
                        rows.push(row);
                    }
                }
            }
            if rows.is_empty() {
                return (
                    "first",
                    values.first().cloned().unwrap_or(JsonValue::Null),
                    json!({
                        "n":          n_present,
                        "n_missing":  n_missing_eff,
                        "note":       "multidim aggregation not applicable for this band (per-cell value isn't an array of floats)",
                    }),
                    "multidim",
                    extra,
                );
            }
            let dim = rows.iter().map(|r| r.len()).min().unwrap_or(0);
            let mut components: Vec<JsonValue> = Vec::with_capacity(dim);
            let mut means: Vec<f64> = Vec::with_capacity(dim);
            for d in 0..dim {
                let col: Vec<f64> = rows
                    .iter()
                    .filter_map(|r| r.get(d).copied().filter(|x| x.is_finite()))
                    .collect();
                if col.is_empty() {
                    components.push(JsonValue::Null);
                    means.push(0.0);
                    continue;
                }
                let n_d = col.len() as f64;
                let mean = col.iter().sum::<f64>() / n_d;
                let mut sorted = col.clone();
                sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
                let median = if sorted.len() % 2 == 1 {
                    sorted[sorted.len() / 2]
                } else {
                    (sorted[sorted.len() / 2 - 1] + sorted[sorted.len() / 2]) / 2.0
                };
                let min = *sorted.first().unwrap();
                let max = *sorted.last().unwrap();
                components.push(json!({
                    "mean": mean, "median": median, "min": min, "max": max,
                    "n": col.len(),
                }));
                means.push(mean);
            }
            (
                "per_component_mean",
                json!(means),
                json!({
                    "components": components,
                    "n":          rows.len(),
                    "n_missing":  n_missing_eff,
                    "dim":        dim,
                }),
                "multidim",
                extra,
            )
        }
    }
}

/// `GET /v1/at?lat=&lon=&band=…&tslot=…`
/// Generic single-or-multi-band lat/lng lookup. CSV-or-repeated
/// `band` accepted via the `bands` field too.
async fn get_v1_at(
    State(s): State<AppState>,
    Query(q): Query<LatLngQ>,
) -> Result<Json<JsonValue>, ApiError> {
    // Multi-band /v1/at defaults to point (n_cells=1) to keep cost
    // bounded — multi-band × multi-cell explodes the upstream fetch
    // count. Caller can opt in with `n_cells: <n>`.
    let target = q.resolve_target(1).await?;
    let mut bands: Vec<String> = Vec::new();
    if let Some(b) = &q.band {
        bands.push(b.clone());
    }
    if let Some(csv) = &q.bands {
        for tok in csv.split(',').map(|s| s.trim()).filter(|s| !s.is_empty()) {
            if !bands.iter().any(|b| b == tok) {
                bands.push(tok.to_string());
            }
        }
    }
    // Default band-set for /v1/at when neither `band` nor `bands` is
    // supplied — gives an agent that doesn't know what to ask for a
    // useful at-this-point bundle. Mirrors the documented MCP
    // `emem_locate` follow-up suggestions.
    if bands.is_empty() {
        for b in DEFAULT_AT_BANDS {
            bands.push((*b).to_string());
        }
    }
    Ok(Json(
        boring_recall_aggregated(&s, target, &bands, q.tslot).await?,
    ))
}

/// Default multi-band bundle for `/v1/at` when the caller omits both
/// `band` and `bands`. Picks the cheapest-cold-start, best-coverage
/// bands across the registry so a naked `?lat=&lon=` answers
/// something useful instead of an empty hash.
const DEFAULT_AT_BANDS: &[&str] = &[
    "copdem30m.elevation_mean",
    "esa_worldcover.lc_2021",
    "weather.temperature_2m",
];

/// Build a fixed-bands boring response. Used by every named shorthand
/// (/v1/ndvi, /v1/elevation, …). Single-band endpoints default to a
/// 16-cell polygon fan-out when `place` resolves to an OSM feature
/// with extent; the caller can opt out via `n_cells: 1`.
async fn boring_named(
    s: &AppState,
    q: LatLngQ,
    bands: &[&str],
) -> Result<Json<JsonValue>, ApiError> {
    // Single-band endpoints default to 16 sample cells when polygon
    // detected (one upstream fetch × 16 cells fits comfortably under
    // the boring-endpoint latency budget once parallelised).
    let target = q.resolve_target(16).await?;
    let bands_owned: Vec<String> = bands.iter().map(|s| (*s).to_string()).collect();
    Ok(Json(
        boring_recall_aggregated(s, target, &bands_owned, q.tslot).await?,
    ))
}

/// `GET /v1/ndvi?lat=&lon=` → indices.ndvi
async fn get_v1_ndvi(
    State(s): State<AppState>,
    Query(q): Query<LatLngQ>,
) -> Result<Json<JsonValue>, ApiError> {
    boring_named(&s, q, &["indices.ndvi"]).await
}

/// `GET /v1/elevation?lat=&lon=` — cross-band coherent elevation.
/// Always recalls Cop-DEM (land) + GMRT (ocean bathymetry) +
/// WorldCover (land-cover veto for the "0 m at sea" case) and reports
/// a `validity` derived from the three. Over open ocean the headline
/// `elevation_m` is null + `bathymetry_m` carries the GMRT depth (signed,
/// negative below sea level); over land the headline carries Cop-DEM.
/// All three sub-facts are exposed under `sub_facts`.
async fn get_v1_elevation(
    State(s): State<AppState>,
    Query(q): Query<LatLngQ>,
) -> Result<Json<JsonValue>, ApiError> {
    let target = q.resolve_target(16).await?;
    Ok(Json(elevation_coherent(&s, target).await?))
}

