/// `GET /v1/agent_quickref` — agent-targeted intent-map.
/// One JSON, every common spatial question → which endpoint to call,
/// at what priority, with the trust language that explains *why* the
/// answer is real (signed, content-addressed, dereferenceable).
async fn get_v1_agent_quickref(State(s): State<AppState>) -> Json<JsonValue> {
    let pubkey_b32 = data_encoding::BASE32_NOPAD
        .encode(&s.identity.pubkey.0)
        .to_lowercase();
    Json(json!({
        "schema": "emem.agent_quickref.v1",
        "responder_pubkey_b32": pubkey_b32,
        "use_emem_when": [
            "user mentions a place, a lat/lng, or a cell64",
            "user asks about vegetation, elevation, air quality, soil, surface water, forest, weather at a point",
            "user wants to verify a spatial claim ('is this address a flood risk?')",
            "user wants to compare or diff two locations or two points in time",
            "user asks 'what is X over Y region' (use POST /v1/recall_polygon)",
        ],
        "trust_guarantees": [
            "Every read returns a signed receipt (ed25519). Cite receipt.fact_cids[0] and the responder pubkey in your reply.",
            "Identical canonical facts have identical CIDs across responders — answers are reproducible.",
            "Signed Absence is a real answer ('tried and got no answer'); do not retry.",
            "Data fidelity is the SENSOR pitch. `data_resolution_m=10` for Sentinel-1/2 indices means the value comes from a real 10 m pixel — not interpolated, not coarsened. The multimodal-fusion contract guarantees that algorithms anchored on S1/S2/Landsat consume 10 m inputs natively.",
            "`cell_dedupe_m` is the cell64 grid grain (~10 m × ~10 m square at the equator, matching S1/S2 native pitch). Two queries 12 m apart land in distinct cells, so values don't silently dedupe across sub-cell points. For coarser sources (Cop-DEM 90 m, SoilGrids 250 m, MODIS 1 km), adjacent cells share the upstream sample — that is correct, not a bug.",
            "No API keys at the request path. Every materializer reads from a no-key public source (Sentinel-1/2, MODIS, NASA POWER, ERA5, CAMS, met.no, JRC GSW, Hansen, ESA WorldCover, SoilGrids, Overture, Cop-DEM, GMRT).",
        ],
        "boring_endpoints": [
            { "intent": "vegetation",      "priority": 1, "method": "GET", "path": "/v1/ndvi",      "params": ["lat","lon"], "returns": "indices.ndvi (Sentinel-2 L2A, 10 m input, ~10 m square cell64 grid)" },
            { "intent": "elevation",       "priority": 1, "method": "GET", "path": "/v1/elevation", "params": ["lat","lon"], "returns": "Cop-DEM 30 m elevation (Open-Meteo Elevation REST)" },
            { "intent": "air_quality",     "priority": 1, "method": "GET", "path": "/v1/air",       "params": ["lat","lon"], "returns": "cams.pm25 + cams.no2 + cams.o3 (Open-Meteo CAMS, hourly 2013-08+)" },
            { "intent": "land_surface_temperature", "priority": 2, "method": "GET", "path": "/v1/lst", "params": ["lat","lon"], "returns": "MODIS LST day + night 8-day (1 km, MOD11A2)" },
            { "intent": "soil_intelligence", "priority": 1, "method": "GET", "path": "/v1/soil",    "params": ["lat","lon"], "returns": "SoilGrids 2.0 SOC + pH + clay + sand + BDOD + N (0–30 cm; ISRIC, 250 m)" },
            { "intent": "surface_water",   "priority": 1, "method": "GET", "path": "/v1/water",     "params": ["lat","lon"], "returns": "JRC GSW recurrence (1984–2021) + S1 VV when available" },
            { "intent": "forest",          "priority": 1, "method": "GET", "path": "/v1/forest",    "params": ["lat","lon"], "returns": "Hansen tree_cover_2000 + loss_year + ESA WorldCover 2021 class" },
            { "intent": "weather_now",     "priority": 1, "method": "GET", "path": "/v1/weather",   "params": ["lat","lon"], "returns": "met.no nowcast: t2m + precip + wind + RH" },
            { "intent": "any_band",        "priority": 2, "method": "GET", "path": "/v1/at",        "params": ["lat","lon","band"], "returns": "any of the 101 materializable bands by name" }
        ],
        "deep_endpoints": [
            { "intent": "single_cell_recall",   "method": "POST", "path": "/v1/recall",         "use_when": "you have a cell64 already, or want multi-band batch in one call" },
            { "intent": "regional_aggregate",  "method": "POST", "path": "/v1/recall_polygon", "use_when": "user named a wide region (city/park/country); collapses locate→sample→recall_many" },
            { "intent": "fan_out_cells",       "method": "POST", "path": "/v1/recall_many",    "use_when": "you have a list of cell64s (max 256) and want one round-trip" },
            { "intent": "history_window",      "method": "POST", "path": "/v1/backfill",       "use_when": "user wants per-tslot history (call /v1/data_availability first)" },
            { "intent": "trajectory",          "method": "POST", "path": "/v1/trajectory",     "use_when": "show how a value moved across attested tslots" },
            { "intent": "diff",                "method": "POST", "path": "/v1/diff",           "use_when": "compare a band at two tslots in the same cell" },
            { "intent": "verify_claim",        "method": "POST", "path": "/v1/verify",         "use_when": "user makes a structured spatial claim ('elevation > 3000 m at X')" },
            { "intent": "knn_similar",         "method": "POST", "path": "/v1/find_similar",   "use_when": "'find places like X' — k-NN over geotessera or any vector band" },
            { "intent": "place_to_cell64",     "method": "POST", "path": "/v1/locate",         "use_when": "you only have a place name or lat/lng and need cell64" },
        ],
        "discovery_endpoints": [
            "GET  /openapi.json           — OpenAPI 3.1 spec (Custom GPT Action)",
            "GET  /.well-known/ai-plugin.json — ChatGPT plugin manifest",
            "GET  /.well-known/emem.json  — protocol manifest CIDs + responder pubkey",
            "POST /mcp                    — MCP Streamable HTTP (Claude / Cursor / Cline / Codex / Antigravity)",
            "GET  /v1/agent_card          — tool catalogue with when-to-use hints",
            "GET  /v1/grid_info           — authoritative cell resolution + spec target",
            "GET  /v1/data_availability   — per-band coverage windows",
            "GET  /v1/algorithms          — 101 composition recipes with citations",
            "GET  /clients.md             — per-client integration guide (this responder, live)",
            "GET  /multimodal.md          — sensor-fusion architecture + validator rules",
        ],
        "citation_pattern": "<value> <unit> at <cell64> (fact_cid <first 8 chars>, signed by responder <first 8 chars of pubkey_b32>; source: <source_url>).",
        "anti_patterns": [
            "Do not invent a fact_cid; if the response is missing one, omit the citation rather than fabricate it.",
            "Do not say 'this is a 305 m measurement' — that was the legacy grid. The active cell64 is ~10 m × ~10 m square at the equator, matching Sentinel-1/Sentinel-2 native pitch. `data_resolution_m` reports the upstream sample (10 m for S1/S2 indices, 90 m Cop-DEM, 250 m SoilGrids, 1 km MODIS LST).",
            "Do not retry on signed Absence — it is the correct answer.",
            "Do not POST to GET endpoints; the boring API is GET-only and idempotent.",
        ],
    }))
}

#[derive(Deserialize)]
struct RecallManyReq {
    /// Cells to fan out across (alias `cell64s` accepted).
    #[serde(alias = "cell64s")]
    cells: Vec<String>,
    /// Optional band filter, applied uniformly to every cell.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    bands: Option<Vec<String>>,
    /// Optional tslot, applied uniformly.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    tslot: Option<u64>,
}

/// `POST /v1/recall_many` — bulk recall in one round trip. The
/// `polygon_sample_cells` field on `/v1/locate` returns up to 64 cells,
/// so a Grand-Canyon agent doing fan-out used to make 64 round trips.
/// This collapses them to one. The response is a per-cell map keyed by
/// cell64; each entry has the same shape as `/v1/recall`.
async fn post_recall_many(
    State(s): State<AppState>,
    Json(mut req): Json<RecallManyReq>,
) -> Result<Json<JsonValue>, ApiError> {
    if req.cells.is_empty() {
        return Err(ApiError(
            StatusCode::BAD_REQUEST,
            ErrorBody {
                code: ErrorCode::InvalidArgument,
                message: "recall_many: `cells` cannot be empty".into(),
                details: None,
            },
        ));
    }
    if req.cells.len() > 256 {
        return Err(ApiError(
            StatusCode::BAD_REQUEST,
            ErrorBody {
                code: ErrorCode::InvalidArgument,
                message: format!(
                    "recall_many: max 256 cells per call (got {}); split client-side",
                    req.cells.len()
                ),
                details: None,
            },
        ));
    }
    // Resolve any place names in the cells array. The result-by-cell
    // map is keyed by the resolved cell64 so a downstream agent can
    // dedupe across heterogeneous inputs ("Tokyo" + "damO.zb000.xUto.sisA"
    // resolve to the same cell and merge into one entry).
    let mut resolved_inputs: Vec<(String, String)> = Vec::with_capacity(req.cells.len()); // (input, cell64)
    for raw in &req.cells {
        let (cell64, _) = resolve_cell_field(raw).await?;
        resolved_inputs.push((raw.clone(), cell64));
    }
    req.cells = resolved_inputs.iter().map(|(_, c)| c.clone()).collect();
    metrics_inc(&RECALL_TOTAL);
    let mut by_cell = serde_json::Map::with_capacity(req.cells.len());
    let mut total_facts = 0usize;
    for cell in &req.cells {
        let r = RecallReq {
            cell: cell.clone(),
            bands: req.bands.clone(),
            tslot: req.tslot,
        };
        match recall(&r, &s).await {
            Ok(resp) => {
                total_facts += resp.facts.len();
                let mut cell_json = serde_json::to_value(&resp).unwrap_or(json!({}));
                // Per-fact band_metadata + value_decoded.
                enrich_facts_with_metadata(&mut cell_json);
                by_cell.insert(cell.clone(), cell_json);
            }
            Err(e) => {
                by_cell.insert(
                    cell.clone(),
                    json!({
                        "error": e.to_string(),
                        "code": e.wire_code(),
                    }),
                );
            }
        }
    }
    let resolved_map: serde_json::Map<String, JsonValue> = resolved_inputs
        .iter()
        .filter(|(input, c)| input != c)
        .map(|(input, c)| (input.clone(), JsonValue::String(c.clone())))
        .collect();
    let mut out = json!({
        "schema": "emem.recall_many.v1",
        "cells_requested": req.cells.len(),
        "facts_returned": total_facts,
        "by_cell": JsonValue::Object(by_cell),
        "note": "Each cell carries its own signed receipt under by_cell.<cell>.receipt. There is no aggregate receipt — verifying any one cell verifies that cell only. To audit the bulk call, verify each cell's receipt independently via /v1/verify_receipt.",
    });
    if !resolved_map.is_empty() {
        if let Some(map) = out.as_object_mut() {
            map.insert("resolved_from".into(), JsonValue::Object(resolved_map));
        }
    }
    Ok(Json(out))
}

/// `POST /v1/recall_polygon` — single call from "place name" or
/// "polygon_bbox" to a fully merged set of facts. Solves the
/// place-name-drift problem at the API level: the agent doesn't have to
/// `/v1/locate` first, read `polygon_sample_cells`, then `/v1/recall_many`
/// — it just hands us a name (or a bbox) plus the bands it wants. We
/// resolve the polygon (via embedded gazetteer → cache → Nominatim,
/// same path as `/v1/locate`), sample up to `max_cells` cells inside
/// the bbox, fan out, and return the per-cell facts plus a flat
/// `merged_facts` array convenient for region-level reasoning.
#[derive(Debug, Clone, Deserialize)]
struct RecallPolygonReq {
    /// Free-text place name (resolved through the same layered geocoder
    /// as `/v1/locate`). One of `place` or `polygon_bbox` is required.
    #[serde(default, alias = "q", alias = "query", alias = "name")]
    place: Option<String>,
    /// Explicit polygon bbox `{min_lat, max_lat, min_lng, max_lng}`. Used
    /// when the caller already has coordinates (e.g. from a polygon
    /// returned by an earlier `/v1/locate`).
    #[serde(default)]
    polygon_bbox: Option<RecallPolygonBbox>,
    /// Bands to recall at every cell in the polygon. Empty / omitted means
    /// "every band attested at the cell" (same as `/v1/recall`).
    #[serde(default, skip_serializing_if = "Option::is_none")]
    bands: Option<Vec<String>>,
    /// Optional uniform tslot.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    tslot: Option<u64>,
    /// Cap on cells sampled from the polygon. Default 64; hard max 1024
    /// (raised from 256 in May 2026 — Katihar test showed a 2 km stride
    /// at 64 cells over a 100 km² PIN-code polygon misses sub-200 m
    /// features like village tanks). The default stays low so naive
    /// callers don't accidentally fan out 1024 materializer fetches.
    #[serde(default)]
    max_cells: Option<usize>,
    /// Target sample density in cells per square kilometre. When set,
    /// the actual cells sampled is `round(cells_per_sqkm × area_km²)`,
    /// clamped to `[1, max_cells]`. Use this for hazard-sweep workflows
    /// where you want a *uniform* spatial resolution regardless of
    /// polygon size: e.g. `cells_per_sqkm=1.0` gives ~1 km stride;
    /// `cells_per_sqkm=4.0` gives ~500 m stride.
    #[serde(default)]
    cells_per_sqkm: Option<f64>,
    /// Two-stage scan: after the coarse fan-out, drill 9-cell sub-grids
    /// centred on each cell whose `surface_water.recurrence` returns
    /// above 25 % (i.e. JRC-classed seasonal/permanent water). Total
    /// cells is still capped at `max_cells`, so the coarse pass uses
    /// `max_cells / 4` budget. Designed for the Katihar use case:
    /// finding sub-cell water bodies missed by uniform sampling. Costs
    /// up to 2x the upstream fetches of a flat scan.
    #[serde(default)]
    drill_on_water: Option<bool>,
    /// Per-fact `band_metadata` opt-in. Default `false`: the response
    /// carries one consolidated `band_metadata` map at the top level
    /// (keyed by band name) so the same metadata isn't duplicated on
    /// every fact across N cells — that duplication added ~8 KB to a
    /// 16-fact response (deepscan finding 2026-05-05). Set `true` to
    /// re-enable per-fact `band_metadata` for backwards compatibility
    /// with callers that walk facts independently. The compact
    /// `value_decoded` label for categorical bands is always emitted
    /// per-fact regardless of this flag.
    #[serde(default)]
    verbose: Option<bool>,
    /// True OSM boundary as GeoJSON `Polygon` or `MultiPolygon`. When
    /// provided, candidate cells from the bbox grid are filtered with
    /// point-in-polygon so the recall scope matches the actual feature
    /// instead of its rectangular envelope. Eliminates the 25–40 %
    /// over-count on L-shaped admin regions and the much larger over-
    /// count on coastal / archipelago features. The `/v1/locate`
    /// response surfaces this value as `polygon_geojson`; agents
    /// chaining locate → recall_polygon should pass it back verbatim.
    /// Falls back to bbox sampling when omitted, malformed, or the
    /// upstream geometry was Point/LineString.
    #[serde(default)]
    polygon_geojson: Option<JsonValue>,
    /// Opt-in supplements. Currently the only recognized token is
    /// `"ftw_fields"` — when present, the response carries an
    /// `ftw_fields` block with per-field agricultural-boundary polygons
    /// from Fields of The World (source.coop global product, CC-BY-4.0)
    /// fetched live for the resolved polygon bbox. Adds ~150–500 ms
    /// cold per query, ~30 ms warm; bounded internally by a 16-tile
    /// per-query cap (split very wide farms into smaller bboxes). On
    /// fetch failure the field is `ftw_fields_error` (string) and the
    /// rest of the response is unaffected.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    include: Option<Vec<String>>,
}

#[derive(Debug, Clone, Deserialize)]
struct RecallPolygonBbox {
    min_lat: f64,
    max_lat: f64,
    min_lng: f64,
    max_lng: f64,
}

/// Request body for `POST /v1/field_boundaries`.  Returns per-field
/// agricultural-boundary polygons from the Fields of The World global
/// product (CC-BY-4.0, source.coop). One of `place` or `polygon_bbox`
/// is required; `place` reuses the same layered geocoder as
/// `/v1/recall_polygon` (embedded → cache → Photon → Nominatim).
#[derive(Debug, Clone, Deserialize)]
struct FieldBoundariesReq {
    #[serde(default, alias = "q", alias = "query", alias = "name")]
    place: Option<String>,
    #[serde(default)]
    polygon_bbox: Option<RecallPolygonBbox>,
    /// Web-Mercator zoom level. Default = library-picked
    /// `min(14, archive.max_zoom)`. Higher zoom = sharper field
    /// boundaries but more tiles per query (capped internally at 16).
    #[serde(default)]
    zoom: Option<u8>,
}

/// `POST /v1/field_boundaries` — fetch FTW agricultural field polygons
/// for a place or bbox. Returns a GeoJSON FeatureCollection plus
/// provenance (source CID, provider URL, license, attribution).
///
/// Why this is a separate primitive from `/v1/recall_polygon?include=ftw_fields`:
/// the latter is the supplement-on-recall shape (returns field polygons
/// *alongside* fan-out recall facts), this is the pure-fetch shape (no
/// recall, no cell sampling — just the per-field geometries). Agents
/// rendering an interactive farm map call this; agents that want
/// "facts at every cell inside the farm + the field polygons" call
/// recall_polygon with the include flag.
async fn post_field_boundaries(
    Json(req): Json<FieldBoundariesReq>,
) -> Result<Json<JsonValue>, ApiError> {
    // Resolve bbox: explicit → place → soft 200 with `needs_location`.
    let (bbox, place_label, via): ((f64, f64, f64, f64), Option<String>, &'static str) =
        if let Some(b) = req.polygon_bbox.as_ref() {
            ((b.min_lat, b.max_lat, b.min_lng, b.max_lng), None, "direct")
        } else if let Some(p) = req.place.as_deref() {
            let lr = LocateReq {
                lat: None,
                lng: None,
                place: Some(p.into()),
            };
            let resp = locate_inner(lr).await?;
            let pb = resp.0.get("polygon_bbox").cloned();
            let lab = resp
                .0
                .get("place_label")
                .and_then(|v| v.as_str())
                .map(|s| s.to_string());
            let v = resp
                .0
                .get("via")
                .and_then(|v| v.as_str())
                .unwrap_or("unknown");
            let via_static: &'static str = match v {
                "embedded" => "embedded",
                "geonames" => "geonames",
                "cache" => "cache",
                "nominatim" => "nominatim",
                "photon" => "photon",
                "direct" => "direct",
                _ => "unknown",
            };
            if let Some(JsonValue::Object(m)) = pb {
                let g = |k: &str| m.get(k).and_then(|v| v.as_f64()).unwrap_or(0.0);
                (
                    (g("min_lat"), g("max_lat"), g("min_lng"), g("max_lng")),
                    lab,
                    via_static,
                )
            } else {
                return Err(ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: format!(
                        "field_boundaries: place '{p}' resolved without a bbox — try passing polygon_bbox explicitly"
                    ),
                    details: None,
                },
            ));
            }
        } else {
            return Ok(Json(json!({
                "schema":  "emem.field_boundaries.v1",
                "status":  "needs_location",
                "message": "no polygon provided. Pass `place` (free-text farm/region name) or `polygon_bbox` ({min_lat, max_lat, min_lng, max_lng}).",
                "examples": [
                    {"place": "Central Valley, California"},
                    {"polygon_bbox": {"min_lat": 36.70, "max_lat": 36.74, "min_lng": -119.84, "max_lng": -119.80}},
                ],
                "agent_hint": "emem_field_boundaries returns per-field agricultural-boundary polygons from the Fields of The World global product (CC-BY-4.0). Best for farm-scale workflows where the OSM/Nominatim polygon would be a single estate envelope.",
            })));
        };
    let b = emem_core::Bbox::new(bbox.0, bbox.1, bbox.2, bbox.3).map_err(|e| {
        ApiError(
            StatusCode::BAD_REQUEST,
            ErrorBody {
                code: ErrorCode::InvalidArgument,
                message: format!("invalid bbox: {e}"),
                details: None,
            },
        )
    })?;
    let coll = emem_fetch::ftw::fetch_field_polygons_bbox(&b, req.zoom)
        .await
        .map_err(|e| {
            ApiError(
                StatusCode::BAD_GATEWAY,
                ErrorBody {
                    code: ErrorCode::SourceFetchFailed,
                    message: format!("ftw fetch: {e}"),
                    details: None,
                },
            )
        })?;
    Ok(Json(json!({
        "schema": "emem.field_boundaries.v1",
        "place": req.place,
        "place_label": place_label,
        "via": via,
        "polygon_bbox": {
            "min_lat": bbox.0, "max_lat": bbox.1,
            "min_lng": bbox.2, "max_lng": bbox.3,
        },
        "count": coll.count,
        "total_area_m2": coll.total_area_m2,
        "zoom_used": coll.zoom_used,
        "tiles_read": coll.tiles_read.iter().map(|(z, x, y)| json!([*z, *x, *y])).collect::<Vec<_>>(),
        "source_cid": coll.source_cid,
        "provider_url": coll.provider_url,
        "license": coll.license,
        "attribution": coll.attribution,
        "geojson": emem_fetch::ftw::to_geojson_feature_collection(&coll),
        "agent_hint": "Per-field agricultural boundaries from Fields of The World (https://fieldsofthe.world). Quote `attribution` and `license` alongside any rendered map. For per-cell recall over the same farm, call POST /v1/recall_polygon with the same polygon_bbox plus `include: [\"ftw_fields\"]` to get both layers in one envelope.",
    })))
}

async fn post_recall_polygon(
    State(s): State<AppState>,
    Json(req): Json<RecallPolygonReq>,
) -> Result<Json<JsonValue>, ApiError> {
    // Polygon geometry, when known. Pulled from the request first
    // (caller already has it from a prior /v1/locate), or — when the
    // caller passed a `place` — recovered from `locate_inner`'s
    // `polygon_geojson` field. Used to mask the bbox-grid candidates
    // via point-in-polygon so we only recall cells inside the true
    // boundary instead of the bounding box envelope.
    let mut polygon_geojson: Option<JsonValue> = req.polygon_geojson.clone();
    // Resolve polygon_bbox: explicit → place lookup → error.
    let (bbox, polygon_source, place_label, via): (
        (f64, f64, f64, f64),
        &'static str,
        Option<String>,
        &'static str,
    ) = if let Some(b) = req.polygon_bbox.as_ref() {
        (
            (b.min_lat, b.max_lat, b.min_lng, b.max_lng),
            "request_polygon_bbox",
            None,
            "direct",
        )
    } else if let Some(p) = req.place.as_deref() {
        // Reuse locate_inner so we get the exact same geocoder layering
        // (embedded → cache → Nominatim) including the wide-bbox table.
        let lr = LocateReq {
            lat: None,
            lng: None,
            place: Some(p.into()),
        };
        let resp = locate_inner(lr).await?;
        // Pull polygon_bbox out; if Nominatim didn't return one, fall back
        // to the centre cell's bbox (single-cell fan-out, basically
        // /v1/recall behaviour but still OK as a degenerate case).
        let pb = resp.0.get("polygon_bbox").cloned();
        // Recover the true polygon geometry — `locate_inner` populates
        // `polygon_geojson` from Nominatim when a real boundary exists.
        // Caller-supplied polygon (req.polygon_geojson) wins; otherwise
        // we adopt whatever locate produced.
        if polygon_geojson.is_none() {
            polygon_geojson = resp
                .0
                .get("polygon_geojson")
                .cloned()
                .filter(|v| !v.is_null());
        }
        let lab = resp
            .0
            .get("place_label")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string());
        let v = resp
            .0
            .get("via")
            .and_then(|v| v.as_str())
            .unwrap_or("unknown");
        let via_static: &'static str = match v {
            "embedded" => "embedded",
            "geonames" => "geonames",
            "cache" => "cache",
            "nominatim" => "nominatim",
            "photon" => "photon",
            "direct" => "direct",
            _ => "unknown",
        };
        if let Some(JsonValue::Object(m)) = pb {
            let g = |k: &str| m.get(k).and_then(|v| v.as_f64()).unwrap_or(0.0);
            let src = m
                .get("source")
                .and_then(|v| v.as_str())
                .unwrap_or("nominatim_boundingbox");
            let src_static: &'static str = match src {
                "wide_bbox_table" => "wide_bbox_table",
                "nominatim_boundingbox" => "nominatim_boundingbox",
                "overture_division_area" => "overture_division_area",
                _ => "geocoder",
            };
            (
                (g("min_lat"), g("max_lat"), g("min_lng"), g("max_lng")),
                src_static,
                lab,
                via_static,
            )
        } else {
            // No polygon — fall back to the locate centre + a tiny epsilon
            // so sample_cells_in_bbox still returns the centre cell.
            let bbox_centre = resp.0.get("bbox_deg").cloned();
            if let Some(JsonValue::Object(m)) = bbox_centre {
                let g = |k: &str| m.get(k).and_then(|v| v.as_f64()).unwrap_or(0.0);
                (
                    (g("min_lat"), g("max_lat"), g("min_lng"), g("max_lng")),
                    "centre_cell_bbox",
                    lab,
                    via_static,
                )
            } else {
                return Err(ApiError(StatusCode::BAD_REQUEST, ErrorBody {
                        code: ErrorCode::InvalidArgument,
                        message: format!("recall_polygon: place '{p}' resolved without bbox or centre — try passing polygon_bbox explicitly"),
                        details: None,
                    }));
            }
        }
    } else {
        // Soft envelope — same rationale as `locate_inner` and `ask_inner`.
        // Return 200 + structured `needs_location` so MCP/Assistants/Vertex
        // hosts route the payload back to the model rather than surfacing
        // a red 4xx toast.
        return Ok(Json(json!({
            "schema":  "emem.recall_polygon.v1",
            "status":  "needs_location",
            "message": "no polygon provided. Pass `place` (free-text place name) or `polygon_bbox` ({min_lat, max_lat, min_lng, max_lng}).",
            "examples": [
                {"place": "Cambridge, UK"},
                {"polygon_bbox": {"min_lat": 52.18, "max_lat": 52.22, "min_lng": 0.10, "max_lng": 0.16}},
            ],
            "next_steps": [
                "if the user named a place, extract the noun phrase and pass it as `place`",
                "if you have a bbox from a previous emem_locate, copy its `polygon_bbox` here",
            ],
            "agent_hint": "emem_recall_polygon collapses locate → polygon_sample_cells → recall_many. The geocoder layering matches /v1/locate.",
        })));
    };

    // Sanity-check the bbox.
    if !(bbox.0.is_finite() && bbox.1.is_finite() && bbox.2.is_finite() && bbox.3.is_finite())
        || bbox.0 > bbox.1
        || bbox.2 > bbox.3
    {
        return Err(ApiError(StatusCode::BAD_REQUEST, ErrorBody {
            code: ErrorCode::InvalidArgument,
            message: format!("recall_polygon: degenerate bbox {bbox:?}; need min_lat ≤ max_lat and min_lng ≤ max_lng with finite values"),
            details: None,
        }));
    }

    // 0.0.3 fix: previously `req.max_cells` was silently clamped, so a
    // caller that asked for 100_000 cells got 1024 with no error and a
    // caller that asked for 0 got 1 with no error. Surface the
    // out-of-range case as 400 so the agent learns its own bug. The
    // 1024 cap matches the documented hard limit (CLIENTS.md §recall).
    let max_cells = match req.max_cells {
        None => 64,
        Some(n) if (1..=1024).contains(&n) => n,
        Some(n) => {
            return Err(ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: format!("recall_polygon: max_cells must be in 1..=1024 (got {n})"),
                    details: None,
                },
            ));
        }
    };
    // Polygon area in km² — for `cells_per_sqkm` density target and for
    // the hint string we surface in the response.
    let area_km2 = {
        let mid_lat = (bbox.0 + bbox.1) / 2.0;
        let lat_km = (bbox.1 - bbox.0) * 111.0;
        let lng_km = (bbox.3 - bbox.2) * 111.0 * mid_lat.to_radians().cos().abs();
        (lat_km * lng_km).max(0.0)
    };
    // If the caller supplied `cells_per_sqkm`, derive n_cells from it
    // (clamped to [1, max_cells]). Otherwise use max_cells directly.
    let target_cells = if let Some(d) = req.cells_per_sqkm {
        if !d.is_finite() || d <= 0.0 {
            return Err(ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: format!("recall_polygon: cells_per_sqkm must be > 0, got {d}"),
                    details: None,
                },
            ));
        }
        ((d * area_km2).round() as usize).clamp(1, max_cells)
    } else {
        max_cells
    };
    let drill = req.drill_on_water.unwrap_or(false);
    // Per-fact `band_metadata` is opt-in — see `RecallPolygonReq::verbose`
    // for rationale. Default false: the response carries a single
    // top-level `band_metadata` map keyed by band name.
    let verbose = req.verbose.unwrap_or(false);
    // Two-stage scan budget: coarse pass gets max(8, target_cells/4),
    // leaving room for the drill phase to fan out.
    let coarse_n = if drill {
        (target_cells / 4).clamp(8, target_cells)
    } else {
        target_cells
    };
    // Polygon mask: when a true boundary is available, filter the
    // bbox-grid candidates via point-in-polygon. Tracked separately
    // for the response so callers can see which path was taken and
    // how many cells the mask discarded — turning silent over-count
    // into a numeric bbox-vs-polygon delta the agent can reason about.
    let parsed_polygons = polygon_geojson
        .as_ref()
        .and_then(parse_polygon_geojson)
        .unwrap_or_default();
    let polygon_mask_kind: &'static str = if parsed_polygons.is_empty() {
        "bbox_only"
    } else {
        "polygon_geojson"
    };
    let mut cells = if parsed_polygons.is_empty() {
        sample_cells_in_bbox(bbox, coarse_n)
    } else {
        sample_cells_in_polygon(bbox, coarse_n, &parsed_polygons)
    };
    if cells.is_empty() {
        return Err(ApiError(
            StatusCode::BAD_REQUEST,
            ErrorBody {
                code: ErrorCode::InvalidArgument,
                message: "recall_polygon: bbox sampled to zero cells".into(),
                details: None,
            },
        ));
    }

    // Fan out. Reuse the same lazy-materialize helper as POST /v1/recall
    // so a cell that hasn't been seeded for a requested band still picks
    // up a fresh signed fact from the registered connector. Without this,
    // recall_polygon at a never-touched region returns zero facts even
    // for bands whose materializer is alive — defeating the whole point.
    metrics_inc(&RECALL_TOTAL);
    let mut by_cell = serde_json::Map::with_capacity(cells.len());
    let mut merged_facts: Vec<JsonValue> = Vec::new();
    let mut total_facts = 0usize;
    let mut materialize_notes_all: Vec<JsonValue> = Vec::new();
    let mut drill_added: Vec<String> = Vec::new();
    for cell in &cells {
        let r = RecallReq {
            cell: cell.clone(),
            bands: req.bands.clone(),
            tslot: req.tslot,
        };
        match recall_with_auto_materialize(&r, &s).await {
            Ok((resp, notes)) => {
                total_facts += resp.facts.len();
                materialize_notes_all.extend(notes);
                if let Ok(mut j) = serde_json::to_value(&resp) {
                    enrich_facts_inner(&mut j, verbose);
                    if let Some(JsonValue::Array(facts)) = j.get("facts").cloned() {
                        merged_facts.extend(facts);
                    }
                    by_cell.insert(cell.clone(), j);
                }
            }
            Err(e) => {
                by_cell.insert(
                    cell.clone(),
                    json!({
                        "error":  e.1.message,
                        "code":   e.1.code,
                        "status": e.0.as_u16(),
                    }),
                );
            }
        }
    }

    // Two-stage drill on water: re-fan around each coarse-pass cell
    // whose surface_water.recurrence > 25 %. The Katihar test (May
    // 2026) showed a 200 m manmade lake fell entirely between the
    // 2 km uniform-stride samples; a coarse-then-drill scan around any
    // recurrence-positive cell catches sub-stride water bodies.
    if drill && total_facts > 0 {
        let coarse_stride_km = if cells.len() > 1 {
            (area_km2 / cells.len() as f64).sqrt()
        } else {
            // Single coarse cell: stride is the bbox side length.
            let mid_lat = (bbox.0 + bbox.1) / 2.0;
            let lat_km = (bbox.1 - bbox.0) * 111.0;
            let lng_km = (bbox.3 - bbox.2) * 111.0 * mid_lat.to_radians().cos().abs();
            lat_km.max(lng_km)
        };
        // Build the list of "hot" coarse cells from the recurrence facts.
        let mut hot_centres: Vec<(f64, f64)> = Vec::new();
        for (cell_str, cell_value) in by_cell.iter() {
            let recurrence = cell_value
                .get("facts")
                .and_then(|f| f.as_array())
                .and_then(|arr| {
                    arr.iter().find_map(|fact| {
                        let band = fact.get("band").and_then(|b| b.as_str())?;
                        if band != "surface_water.recurrence" {
                            return None;
                        }
                        fact.get("value").and_then(|v| v.as_f64())
                    })
                });
            if let Some(rec) = recurrence {
                if rec > 25.0 {
                    if let Ok(info) = emem_codec::latlng_from_cell64(cell_str) {
                        hot_centres.push((info.lat_deg, info.lng_deg));
                    }
                }
            }
        }
        // Drill stride: 1/4 the coarse stride, floor 0.05 km (~50 m).
        let drill_stride_km = (coarse_stride_km / 4.0).max(0.05);
        let mut budget = target_cells.saturating_sub(cells.len());
        let mut new_cells: Vec<String> = Vec::new();
        let mut seen: std::collections::BTreeSet<String> = cells.iter().cloned().collect();
        'drill: for (lat0, lng0) in hot_centres {
            let mid_lat = lat0;
            let lat_step_deg = drill_stride_km / 111.0;
            let lng_step_deg =
                drill_stride_km / (111.0 * mid_lat.to_radians().cos().abs().max(1e-6));
            for di in -2i32..=2 {
                for dj in -2i32..=2 {
                    if di == 0 && dj == 0 {
                        continue;
                    }
                    if budget == 0 {
                        break 'drill;
                    }
                    let la = lat0 + (di as f64) * lat_step_deg;
                    let ln = lng0 + (dj as f64) * lng_step_deg;
                    if la < bbox.0 || la > bbox.1 || ln < bbox.2 || ln > bbox.3 {
                        continue;
                    }
                    let s = emem_codec::to_cell64(emem_codec::cell_from_latlng(la, ln));
                    if seen.insert(s.clone()) {
                        new_cells.push(s);
                        budget -= 1;
                    }
                }
            }
        }
        // Recall the drill cells.
        for cell in &new_cells {
            let r = RecallReq {
                cell: cell.clone(),
                bands: req.bands.clone(),
                tslot: req.tslot,
            };
            match recall_with_auto_materialize(&r, &s).await {
                Ok((resp, notes)) => {
                    total_facts += resp.facts.len();
                    materialize_notes_all.extend(notes);
                    if let Ok(mut j) = serde_json::to_value(&resp) {
                        enrich_facts_inner(&mut j, verbose);
                        if let Some(JsonValue::Array(facts)) = j.get("facts").cloned() {
                            merged_facts.extend(facts);
                        }
                        by_cell.insert(cell.clone(), j);
                    }
                }
                Err(e) => {
                    by_cell.insert(
                        cell.clone(),
                        json!({
                            "error":  e.1.message,
                            "code":   e.1.code,
                            "status": e.0.as_u16(),
                        }),
                    );
                }
            }
        }
        drill_added = new_cells.clone();
        cells.extend(new_cells);
    }

    // Coverage honesty. The polygon area covers `area_km2 / (cell_dedupe_m_squared)`
    // distinct cell64 grid cells at native resolution; we sampled `cells.len()`
    // of them. `is_exhaustive` flips true only when we hit (or exceeded) the
    // native-grid count. `coverage_fraction` is the ratio, clamped to [0, 1].
    // An LLM that prints "Lake Tahoe averaged 1410 m elevation" off a 16-cell
    // sample of a 500 km² polygon should know it's working with a 0.0008
    // coverage fraction, not a wall-to-wall scan.
    let cell_grain_m2 = (RESOLUTION_M_GRID as f64) * (RESOLUTION_M_GRID as f64);
    let total_native_cells = if area_km2 > 0.0 {
        ((area_km2 * 1_000_000.0) / cell_grain_m2).max(1.0)
    } else {
        1.0
    };
    let coverage_fraction = ((cells.len() as f64) / total_native_cells).min(1.0);
    let is_exhaustive = (cells.len() as f64) >= total_native_cells;
    let mut out = json!({
        "schema": "emem.recall_polygon.v1",
        "polygon_bbox": {
            "min_lat": bbox.0, "max_lat": bbox.1,
            "min_lng": bbox.2, "max_lng": bbox.3,
            "source": polygon_source,
        },
        // Which mask was applied to the bbox grid: "polygon_geojson"
        // means cells were filtered against the true OSM boundary via
        // point-in-polygon (precise); "bbox_only" means the bbox
        // envelope was sampled directly (over-inclusive on concave
        // shapes — admin regions, coastal features). Agents that need
        // tight aggregation should pass `polygon_geojson` from
        // `/v1/locate` to flip the mask kind to "polygon_geojson".
        "polygon_mask": polygon_mask_kind,
        "place": req.place,
        "place_label": place_label,
        "via": via,
        "area_km2": area_km2,
        "cells_per_sqkm_effective": if area_km2 > 0.0 { cells.len() as f64 / area_km2 } else { 0.0 },
        "cells_sampled": cells.len(),
        "cells": cells,
        "coverage_fraction": coverage_fraction,
        "is_exhaustive": is_exhaustive,
        "native_grid_cells_in_polygon": total_native_cells,
        "drill_on_water": drill,
        "drill_cells_added": drill_added.len(),
        "facts_returned": total_facts,
        "merged_facts": merged_facts,
        "by_cell": JsonValue::Object(by_cell),
        "next": [
            "Each cell.receipt is independently signed; verify any cell's receipt via POST /v1/verify_receipt.",
            "For region statistics over the merged_facts, POST /v1/query_region with `geometry: \"cells:c1,c2,...\"` and the same bands.",
            "If a sub-cell water body was missed (Katihar lesson), pass `cells_per_sqkm: 4.0` for ~500 m stride, or `drill_on_water: true` for a coarse-then-drill scan around recurrence-positive cells.",
            "max_cells hard-cap is 1024 (raised May 2026); default stays 64.",
        ],
        "agent_hint": "POST /v1/recall_polygon collapses /v1/locate → polygon_sample_cells → /v1/recall_many into one call. The bbox source is declared so an agent can detect when the geocoder fell back from polygon (Nominatim bbox) to a single-cell centroid (place-name drift mitigation: fail loud, not silent). Set `cells_per_sqkm` for a uniform spatial resolution; set `drill_on_water: true` to find sub-stride water features.",
    });
    if !materialize_notes_all.is_empty() {
        if let Some(m) = out.as_object_mut() {
            m.insert(
                "materialize_notes".into(),
                JsonValue::Array(materialize_notes_all),
            );
        }
    }
    // When verbose=false (the default), hoist a single `band_metadata`
    // map keyed by band name onto the response root. The same blob
    // would otherwise be duplicated on every fact across N cells —
    // ~8 KB on a 16-fact response (deepscan finding 2026-05-05).
    // With verbose=true, the per-fact form is preserved and we skip
    // the top-level block to avoid sending the same data twice.
    if !verbose {
        let bands_present = unique_band_keys_in_facts(&out["merged_facts"]);
        if !bands_present.is_empty() {
            let mut meta_map = serde_json::Map::with_capacity(bands_present.len());
            for b in bands_present {
                let m = band_metadata_for_response(&b);
                if !m.is_null() {
                    meta_map.insert(b, m);
                }
            }
            if !meta_map.is_empty() {
                if let Some(o) = out.as_object_mut() {
                    o.insert("band_metadata".into(), JsonValue::Object(meta_map));
                    o.insert(
                        "band_metadata_layout".into(),
                        json!("hoisted: keyed by band; pass `verbose:true` to inline per-fact"),
                    );
                }
            }
        }
    }
    // Opt-in Fields of The World agricultural-boundary supplement.
    // When the caller passes `include: ["ftw_fields"]` and the bbox is
    // within Web-Mercator range, we fetch per-field polygons from the
    // FTW global PMTiles archive (CC-BY-4.0, source.coop, anonymous)
    // and attach them under `ftw_fields`. Fetch failures are surfaced
    // as a sibling `ftw_fields_error` string rather than failing the
    // whole recall — agents that don't need the supplement should not
    // see a regression when FTW is temporarily unreachable.
    let want_ftw = req
        .include
        .as_ref()
        .map(|v| v.iter().any(|s| s.eq_ignore_ascii_case("ftw_fields")))
        .unwrap_or(false);
    if want_ftw {
        match emem_core::Bbox::new(bbox.0, bbox.1, bbox.2, bbox.3) {
            Ok(b) => match emem_fetch::ftw::fetch_field_polygons_bbox(&b, None).await {
                Ok(coll) => {
                    if let Some(o) = out.as_object_mut() {
                        o.insert(
                            "ftw_fields".into(),
                            json!({
                                "schema": "emem.ftw_fields.v1",
                                "count": coll.count,
                                "total_area_m2": coll.total_area_m2,
                                "zoom_used": coll.zoom_used,
                                "tiles_read": coll.tiles_read.iter().map(|(z, x, y)| json!([*z, *x, *y])).collect::<Vec<_>>(),
                                "source_cid": coll.source_cid,
                                "provider_url": coll.provider_url,
                                "license": coll.license,
                                "attribution": coll.attribution,
                                "geojson": emem_fetch::ftw::to_geojson_feature_collection(&coll),
                            }),
                        );
                    }
                }
                Err(e) => {
                    if let Some(o) = out.as_object_mut() {
                        o.insert("ftw_fields_error".into(), json!(e.to_string()));
                    }
                }
            },
            Err(e) => {
                if let Some(o) = out.as_object_mut() {
                    o.insert(
                        "ftw_fields_error".into(),
                        json!(format!("invalid bbox for FTW: {e}")),
                    );
                }
            }
        }
    }
    Ok(Json(out))
}

/// Loose body for `POST /v1/query_region`. Accepts the protocol's
/// canonical `geometry` shape (cell64 string or `cells:c1,c2,...`)
/// AND a `bbox` shape (`[west, south, east, north]` in WGS-84
/// degrees) for parity with /v1/recall_polygon and the documented
/// agent-walkthroughs examples. When `bbox` is present we sample it
/// to a cell list via the same `sample_cells_in_bbox` helper
/// /v1/recall_polygon uses, then pass to the canonical primitive
/// under `cells:` notation. Either `geometry` or `bbox` is required.
#[derive(Deserialize)]
struct QueryRegionRestReq {
    #[serde(default)]
    geometry: Option<String>,
    /// `[west, south, east, north]` (WGS-84 degrees). Mutually
    /// exclusive with `geometry`; if both are supplied, `geometry`
    /// wins (so the canonical-shape contract is unchanged).
    #[serde(default)]
    bbox: Option<[f64; 4]>,
    #[serde(default)]
    bands: Option<Vec<String>>,
    #[serde(default)]
    agg: Option<String>,
    /// Optional cap on cells materialized from a bbox, to keep a wide
    /// region from blowing the request budget. Defaults to 256 (the
    /// same cap /v1/recall_many enforces).
    #[serde(default)]
    max_cells: Option<usize>,
}

async fn post_query_region(
    State(s): State<AppState>,
    Json(req): Json<QueryRegionRestReq>,
) -> Result<Json<JsonValue>, ApiError> {
    // Convert the loose REST shape into the canonical primitive shape.
    let geometry = if let Some(g) = req.geometry.as_deref().filter(|s| !s.is_empty()) {
        g.to_string()
    } else if let Some(bb) = req.bbox {
        // bbox is `[west, south, east, north]` (longitude first, the
        // GeoJSON convention `examples/agent-walkthroughs.md` uses).
        // sample_cells_in_bbox takes `(min_lat, max_lat, min_lng, max_lng)`.
        let (west, south, east, north) = (bb[0], bb[1], bb[2], bb[3]);
        if !west.is_finite() || !south.is_finite() || !east.is_finite() || !north.is_finite() {
            return Err(ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: "bbox values must be finite (got NaN/Inf)".into(),
                    details: None,
                },
            ));
        }
        if west > east || south > north {
            return Err(ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: format!(
                        "bbox must be [west, south, east, north] with west<=east and south<=north; got {bb:?}"
                    ),
                    details: None,
                },
            ));
        }
        // Default cap is bbox-area driven so a small park (~1 km²) doesn't
        // pay the full 256-cell cost while a large region (~10 000 km²)
        // gets a denser sample. Clamped to [64, 1024]; honoured `max_cells`
        // when the caller specifies one. The cap nominally targets
        // ~1 cell per (10 km)² of area at the present grid resolution
        // (~9.55 m pitch → ~10⁴ cells per km², so a 1024-cell cap covers
        // ~0.1 km² densely or ~1 cell per km² across a 1000 km² region —
        // good enough for representative sampling while keeping the
        // upstream fetch count bounded).
        let cap = req.max_cells.unwrap_or_else(|| {
            let mid_lat = (south + north) * 0.5;
            let lat_km = (north - south).abs() * 111.0;
            let lng_km = (east - west).abs() * 111.0 * mid_lat.to_radians().cos().abs();
            let area_km2 = lat_km * lng_km;
            // 1 cell per (10 km)² target, clamped [64, 1024].
            ((area_km2 / 100.0).round() as i64).clamp(64, 1024) as usize
        }).clamp(1, 1024);
        let cells = sample_cells_in_bbox((south, north, west, east), cap);
        if cells.is_empty() {
            return Err(ApiError(
                StatusCode::BAD_REQUEST,
                ErrorBody {
                    code: ErrorCode::InvalidArgument,
                    message: "bbox sampled to zero cells; widen the bbox or check axis order ([west, south, east, north])".into(),
                    details: None,
                },
            ));
        }
        format!("cells:{}", cells.join(","))
    } else {
        return Err(ApiError(
            StatusCode::BAD_REQUEST,
            ErrorBody {
                code: ErrorCode::InvalidArgument,
                message: "POST /v1/query_region requires `geometry` (cell64 or `cells:c1,c2,...`) OR `bbox` ([west, south, east, north] in WGS-84 degrees)".into(),
                details: None,
            },
        ));
    };
    let inner = QueryRegionReq {
        geometry,
        bands: req.bands,
        agg: req.agg,
    };
    let resp = query_region(&inner, &s).await?;
    Ok(Json(serde_json::to_value(resp).unwrap_or(json!({}))))
}

/// Build a `resolved_from` JSON object surfacing every place name we
/// substituted for a cell64. Empty when every input was already a cell64.
fn resolved_envelope(entries: Vec<(String, ResolvedRef)>) -> Option<JsonValue> {
    let mut out = serde_json::Map::new();
    for (field, r) in entries {
        if matches!(r, ResolvedRef::Place { .. }) {
            out.insert(field, serde_json::to_value(&r).unwrap_or(JsonValue::Null));
        }
    }
    if out.is_empty() {
        None
    } else {
        Some(JsonValue::Object(out))
    }
}

fn attach_resolved(mut body: JsonValue, env: Option<JsonValue>) -> JsonValue {
    if let (Some(env), Some(map)) = (env, body.as_object_mut()) {
        map.insert("resolved_from".into(), env);
    }
    body
}

async fn post_compare(
    State(s): State<AppState>,
    Json(mut req): Json<CompareReq>,
) -> Result<Json<JsonValue>, ApiError> {
    // Accept place names in either side. `compare {a:"Tokyo", b:"Mumbai"}`
    // now works without the agent having to call `emem_locate` twice first.
    let (a_cell, ra) = resolve_cell_field(&req.a).await?;
    let (b_cell, rb) = resolve_cell_field(&req.b).await?;
    req.a = a_cell;
    req.b = b_cell;
    let resp = compare(&req, &s).await?;
    let env = resolved_envelope(vec![("a".into(), ra), ("b".into(), rb)]);
    Ok(Json(attach_resolved(
        serde_json::to_value(resp).unwrap_or(json!({})),
        env,
    )))
}

